const Q_SR_BIOLOGY=[{"id":"srb111001","state":"AU","section":"sr_biology","grade":"11","topic":"Biomolecules","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Which biomolecule serves as the primary long-term energy storage molecule in animal cells?","options":["protein","lipid (fat)","nucleic acid","glycogen, a type of carbohydrate"],"answer":1,"exp":"Lipids (fats) serve as the primary long-term energy storage molecule in animal cells, storing more energy per gram than carbohydrates or proteins."},{"id":"srb111002","state":"AU","section":"sr_biology","grade":"11","topic":"Biomolecules","difficulty":"hard","style":"standard","paper":"G11-B1","q":"What is the monomer (basic building block) of a protein?","options":["glucose","amino acids","nucleotides","fatty acids"],"answer":1,"exp":"Amino acids are the monomers that link together to form proteins, joined by peptide bonds."},{"id":"srb111003","state":"AU","section":"sr_biology","grade":"11","topic":"Biomolecules","difficulty":"hard","style":"standard","paper":"G11-B1","q":"What is the monomer (basic building block) of DNA and RNA?","options":["amino acids","fatty acids","nucleotides","monosaccharides"],"answer":2,"exp":"Nucleotides are the monomers that link together to form nucleic acids like DNA and RNA, each made of a sugar, phosphate group, and nitrogenous base."},{"id":"srb111004","state":"AU","section":"sr_biology","grade":"11","topic":"Biomolecules","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Which type of bond joins two amino acids together in a protein chain?","options":["a glycosidic bond","a peptide bond","an ester bond","a hydrogen bond only"],"answer":1,"exp":"A peptide bond forms between the carboxyl group of one amino acid and the amino group of the next, linking amino acids into a chain."},{"id":"srb111005","state":"AU","section":"sr_biology","grade":"11","topic":"Cell Structure","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Which of these best describes the structure of a phospholipid, the main component of cell membranes?","options":["a hydrophilic head and two hydrophobic tails","two hydrophilic heads with no tail","a single long chain of amino acids","a ring structure made entirely of carbon"],"answer":0,"exp":"A phospholipid has a hydrophilic (water-attracting) phosphate head and two hydrophobic (water-repelling) fatty acid tails, which is why phospholipids spontaneously arrange into a bilayer in water."},{"id":"srb111006","state":"AU","section":"sr_biology","grade":"11","topic":"Cell Structure","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Why does the phospholipid bilayer arrange itself with hydrophobic tails facing inward?","options":["this arrangement has no particular benefit","the hydrophobic tails avoid contact with the surrounding watery environment, while the hydrophilic heads face outward toward the water","hydrophobic tails are attracted to water","this arrangement only occurs in plant cells"],"answer":1,"exp":"The hydrophobic tails avoid contact with the surrounding watery (aqueous) environment by facing inward, while the hydrophilic heads face outward toward the water on both sides of the membrane."},{"id":"srb111007","state":"AU","section":"sr_biology","grade":"11","topic":"Cell Structure","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Which organelle is responsible for producing ATP through aerobic respiration?","options":["the nucleus","the mitochondria","the Golgi apparatus","the ribosome"],"answer":1,"exp":"Mitochondria are responsible for producing ATP (the cell's main energy currency) through the process of aerobic respiration."},{"id":"srb111008","state":"AU","section":"sr_biology","grade":"11","topic":"Cell Structure","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Which organelle modifies, sorts, and packages proteins for secretion or use elsewhere in the cell?","options":["the lysosome","the Golgi apparatus","the mitochondria","the nucleus"],"answer":1,"exp":"The Golgi apparatus modifies, sorts, and packages proteins (often received from the rough endoplasmic reticulum) for secretion or use elsewhere in the cell."},{"id":"srb111009","state":"AU","section":"sr_biology","grade":"11","topic":"Cell Structure","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Which structure within a cell is the site of protein synthesis?","options":["the ribosome","the lysosome","the vacuole","the centriole"],"answer":0,"exp":"Ribosomes are the site of protein synthesis, translating mRNA into chains of amino acids."},{"id":"srb111010","state":"AU","section":"sr_biology","grade":"11","topic":"Cell Structure","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Which organelle contains digestive enzymes used to break down waste materials and cellular debris?","options":["the lysosome","the mitochondria","the nucleus","the Golgi apparatus"],"answer":0,"exp":"Lysosomes contain digestive enzymes used to break down waste materials, cellular debris, and worn-out organelles."},{"id":"srb111011","state":"AU","section":"sr_biology","grade":"11","topic":"Cell Structure","difficulty":"hard","style":"standard","paper":"G11-B1","q":"What is the difference between rough and smooth endoplasmic reticulum?","options":["there is no real difference between them","rough ER is studded with ribosomes and involved in protein synthesis, while smooth ER lacks ribosomes and is involved in lipid synthesis and detoxification","rough ER is found only in plant cells","smooth ER is responsible for cell division"],"answer":1,"exp":"Rough ER is studded with ribosomes and is involved in synthesising and processing proteins, while smooth ER lacks ribosomes and is involved in lipid synthesis and detoxification processes."},{"id":"srb111012","state":"AU","section":"sr_biology","grade":"11","topic":"Cell Structure","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Which best describes the fluid mosaic model of the cell membrane?","options":["the membrane is a completely rigid, fixed structure","the membrane consists of a flexible phospholipid bilayer with embedded proteins that can move within the layer","the membrane is made entirely of protein with no lipid component","the membrane has no defined structure at all"],"answer":1,"exp":"The fluid mosaic model describes the cell membrane as a flexible phospholipid bilayer with embedded proteins that can move laterally within the layer, giving the membrane both fluidity and a 'mosaic' of different components."},{"id":"srb111013","state":"AU","section":"sr_biology","grade":"11","topic":"Cell Structure","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Which type of membrane protein spans the entire width of the membrane and can act as a channel for specific molecules?","options":["a peripheral protein","an integral (transmembrane) protein","a glycoprotein only","a phospholipid"],"answer":1,"exp":"Integral (transmembrane) proteins span the entire width of the membrane and can act as channels or carriers, allowing specific molecules to cross."},{"id":"srb111014","state":"AU","section":"sr_biology","grade":"11","topic":"Cell Transport","difficulty":"hard","style":"standard","paper":"G11-B1","q":"What is 'osmosis'?","options":["the movement of solute particles from low to high concentration","the diffusion of water across a selectively permeable membrane, from an area of higher water concentration to lower water concentration","the active transport of proteins out of a cell","a type of cell division"],"answer":1,"exp":"Osmosis is the diffusion of water across a selectively permeable membrane, moving from an area of higher water concentration (lower solute concentration) to an area of lower water concentration (higher solute concentration)."},{"id":"srb111015","state":"AU","section":"sr_biology","grade":"11","topic":"Cell Transport","difficulty":"hard","style":"standard","paper":"G11-B1","q":"What happens to an animal cell placed in a hypertonic solution (higher solute concentration outside the cell)?","options":["the cell swells and may burst","the cell loses water and shrinks (crenation)","the cell remains completely unchanged","the cell immediately divides"],"answer":1,"exp":"In a hypertonic solution, water moves out of the cell (from lower to higher solute concentration outside), causing the cell to lose water and shrink, a process called crenation in animal cells."},{"id":"srb111016","state":"AU","section":"sr_biology","grade":"11","topic":"Cell Transport","difficulty":"hard","style":"standard","paper":"G11-B1","q":"What happens to a plant cell placed in a hypotonic solution (lower solute concentration outside the cell)?","options":["the cell shrinks significantly","water enters the cell, but the rigid cell wall prevents bursting, resulting in a turgid (firm) cell","the cell wall dissolves completely","nothing happens at all"],"answer":1,"exp":"In a hypotonic solution, water enters the plant cell by osmosis, but the rigid cell wall prevents the cell from bursting, resulting in a firm, turgid cell."},{"id":"srb111017","state":"AU","section":"sr_biology","grade":"11","topic":"Cell Transport","difficulty":"hard","style":"standard","paper":"G11-B1","q":"What is 'active transport' across a cell membrane?","options":["the movement of molecules down their concentration gradient, requiring no energy","the movement of molecules against their concentration gradient, requiring energy input (usually from ATP)","a type of passive diffusion","a process that only occurs in plant cells"],"answer":1,"exp":"Active transport moves molecules against their concentration gradient (from low to high concentration), which requires energy input, usually supplied by ATP."},{"id":"srb111018","state":"AU","section":"sr_biology","grade":"11","topic":"Cell Transport","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Which best describes 'facilitated diffusion'?","options":["the diffusion of molecules directly through the phospholipid bilayer without any assistance","the diffusion of molecules across a membrane with the assistance of specific transport proteins, still moving down their concentration gradient","a type of active transport requiring ATP","a process exclusive to plant cells"],"answer":1,"exp":"Facilitated diffusion involves the diffusion of molecules across a membrane with the assistance of specific transport proteins (channels or carriers), but still moving down their concentration gradient without requiring energy input."},{"id":"srb111019","state":"AU","section":"sr_biology","grade":"11","topic":"Biomolecules — Enzymes","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Which best describes the role of enzymes in biochemical reactions?","options":["enzymes are consumed and destroyed during the reaction they catalyse","enzymes act as biological catalysts, lowering the activation energy required for a reaction without being consumed","enzymes always slow down biochemical reactions","enzymes have no real biological function"],"answer":1,"exp":"Enzymes act as biological catalysts, lowering the activation energy required for a reaction to proceed, without being consumed or permanently altered by the reaction."},{"id":"srb111020","state":"AU","section":"sr_biology","grade":"11","topic":"Biomolecules — Enzymes","difficulty":"hard","style":"standard","paper":"G11-B1","q":"What is the 'active site' of an enzyme?","options":["the entire surface of the enzyme molecule","the specific region of an enzyme where the substrate binds and the reaction occurs","a structure found only in plant enzymes","a region that has no functional significance"],"answer":1,"exp":"The active site is the specific region of an enzyme where a substrate molecule binds, and where the catalysed reaction actually takes place."},{"id":"srb111021","state":"AU","section":"sr_biology","grade":"11","topic":"Biomolecules — Enzymes","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Which best explains why enzyme activity typically decreases at temperatures significantly above an enzyme's optimal temperature?","options":["the enzyme works more efficiently at higher temperatures with no limit","excessive heat can cause the enzyme to denature, altering its shape and reducing its ability to bind its substrate","temperature has no effect on enzyme activity","enzymes are never affected by temperature changes"],"answer":1,"exp":"Excessive heat can cause an enzyme to denature — its three-dimensional shape becomes altered or disrupted — which reduces or eliminates its ability to bind its substrate effectively."},{"id":"srb111022","state":"AU","section":"sr_biology","grade":"11","topic":"Biomolecules — Enzymes","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Which best describes a 'competitive inhibitor' of an enzyme?","options":["a molecule that binds to a site other than the active site, changing the enzyme's shape","a molecule with a similar shape to the substrate, which competes for binding at the enzyme's active site","a molecule that always increases enzyme activity","a structural component of all enzymes"],"answer":1,"exp":"A competitive inhibitor has a similar shape to the substrate, allowing it to compete directly for binding at the enzyme's active site, thereby blocking the substrate from binding and reducing the reaction rate."},{"id":"srb111023","state":"AU","section":"sr_biology","grade":"11","topic":"Biomolecules — Enzymes","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Which best describes a 'non-competitive inhibitor' of an enzyme?","options":["a molecule that binds at the active site itself","a molecule that binds to a different site on the enzyme, changing its shape so the substrate can no longer bind effectively at the active site","a molecule with no effect on enzyme activity","a type of substrate, not an inhibitor"],"answer":1,"exp":"A non-competitive inhibitor binds to a different site on the enzyme (not the active site), changing the enzyme's overall shape so the substrate can no longer bind effectively at the active site."},{"id":"srb111024","state":"AU","section":"sr_biology","grade":"11","topic":"Biomolecules — Enzymes","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Which best describes why a high concentration of substrate eventually leads to a plateau in reaction rate, rather than continuing to increase indefinitely?","options":["substrate concentration has no relationship to reaction rate","once all available enzyme active sites are saturated with substrate, adding more substrate cannot further increase the reaction rate","reaction rate always increases indefinitely with more substrate","enzymes are destroyed at high substrate concentrations"],"answer":1,"exp":"Once all available enzyme active sites are saturated (occupied) with substrate, adding more substrate cannot further increase the reaction rate, since there are no free active sites left to bind additional substrate molecules."},{"id":"srb111025","state":"AU","section":"sr_biology","grade":"11","topic":"Cell Structure","difficulty":"hard","style":"standard","paper":"G11-B1","q":"Which best describes the difference between a prokaryotic and eukaryotic cell?","options":["prokaryotic cells have a true nucleus, while eukaryotic cells do not","eukaryotic cells have a true, membrane-bound nucleus and other membrane-bound organelles, while prokaryotic cells lack these structures","there is no meaningful structural difference between them","prokaryotic cells are always larger than eukaryotic cells"],"answer":1,"exp":"Eukaryotic cells have a true, membrane-bound nucleus and various other membrane-bound organelles, while prokaryotic cells (such as bacteria) lack these structures, with their genetic material existing freely within the cytoplasm."},{"id":"srb112001","state":"AU","section":"sr_biology","grade":"11","topic":"Cellular Respiration","difficulty":"hard","style":"standard","paper":"G11-B2","q":"What is the overall purpose of cellular respiration?","options":["to produce glucose from carbon dioxide","to release energy stored in glucose, converting it into a usable form (ATP)","to absorb sunlight for energy","to produce oxygen as a primary product"],"answer":1,"exp":"Cellular respiration releases the energy stored in glucose, converting it into ATP, a usable form of energy for the cell's processes."},{"id":"srb112002","state":"AU","section":"sr_biology","grade":"11","topic":"Cellular Respiration","difficulty":"hard","style":"standard","paper":"G11-B2","q":"Which of these is the correct overall equation for aerobic cellular respiration?","options":["6CO₂ + 6H₂O → C₆H₁₂O₆ + 6O₂","C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + energy (ATP)","C₆H₁₂O₆ → 2C₂H₅OH + 2CO₂","6H₂O + 6O₂ → C₆H₁₂O₆ + 6CO₂"],"answer":1,"exp":"Aerobic respiration breaks down glucose using oxygen, producing carbon dioxide, water, and energy: C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + energy."},{"id":"srb112003","state":"AU","section":"sr_biology","grade":"11","topic":"Cellular Respiration","difficulty":"hard","style":"standard","paper":"G11-B2","q":"In which part of the cell does glycolysis (the first stage of cellular respiration) take place?","options":["the mitochondrial matrix","the cytoplasm","the nucleus","the cell membrane"],"answer":1,"exp":"Glycolysis takes place in the cytoplasm of the cell, breaking down glucose into two molecules of pyruvate."},{"id":"srb112004","state":"AU","section":"sr_biology","grade":"11","topic":"Cellular Respiration","difficulty":"hard","style":"standard","paper":"G11-B2","q":"What are the main products of glycolysis?","options":["carbon dioxide and water only","two molecules of pyruvate, a small amount of ATP, and NADH","oxygen and glucose","six molecules of carbon dioxide"],"answer":1,"exp":"Glycolysis breaks down one glucose molecule into two pyruvate molecules, while also producing a small net amount of ATP and NADH (an electron carrier)."},{"id":"srb112005","state":"AU","section":"sr_biology","grade":"11","topic":"Cellular Respiration","difficulty":"hard","style":"standard","paper":"G11-B2","q":"In which part of the mitochondria does the Krebs cycle (citric acid cycle) take place?","options":["the outer mitochondrial membrane","the mitochondrial matrix","the cytoplasm","the nucleus"],"answer":1,"exp":"The Krebs cycle takes place in the mitochondrial matrix, the fluid-filled space inside the inner mitochondrial membrane."},{"id":"srb112006","state":"AU","section":"sr_biology","grade":"11","topic":"Cellular Respiration","difficulty":"hard","style":"standard","paper":"G11-B2","q":"What is the role of the electron transport chain in aerobic respiration?","options":["to produce glucose from carbon dioxide","to use electron carriers (NADH and FADH₂) to generate a large amount of ATP, with oxygen as the final electron acceptor","to break down glucose into pyruvate","to release carbon dioxide directly without any further chemical steps"],"answer":1,"exp":"The electron transport chain uses electron carriers (NADH and FADH₂) generated in earlier stages to power ATP production, with oxygen serving as the final electron acceptor, forming water."},{"id":"srb112007","state":"AU","section":"sr_biology","grade":"11","topic":"Cellular Respiration","difficulty":"hard","style":"standard","paper":"G11-B2","q":"Why is oxygen essential for aerobic respiration to continue efficiently?","options":["oxygen has no real role in aerobic respiration","oxygen acts as the final electron acceptor in the electron transport chain, allowing this chain to keep functioning and generating large amounts of ATP","oxygen is used to produce glucose","oxygen is only needed during glycolysis"],"answer":1,"exp":"Oxygen acts as the final electron acceptor in the electron transport chain. Without oxygen, this chain backs up and stops functioning, severely limiting ATP production."},{"id":"srb112008","state":"AU","section":"sr_biology","grade":"11","topic":"Cellular Respiration — Anaerobic","difficulty":"hard","style":"standard","paper":"G11-B2","q":"What happens during anaerobic respiration (fermentation) in human muscle cells, when oxygen is in short supply?","options":["glucose is fully broken down into carbon dioxide and water","pyruvate is converted into lactic acid, allowing glycolysis to continue without oxygen, though producing much less ATP","oxygen is produced as a by-product","muscle cells stop producing any ATP at all"],"answer":1,"exp":"In human muscle cells without sufficient oxygen, pyruvate is converted into lactic acid, which allows glycolysis to continue and produce a small amount of ATP, though far less efficiently than aerobic respiration."},{"id":"srb112009","state":"AU","section":"sr_biology","grade":"11","topic":"Cellular Respiration","difficulty":"hard","style":"standard","paper":"G11-B2","q":"Approximately how much more ATP is produced per glucose molecule through aerobic respiration compared to anaerobic respiration (fermentation)?","options":["about the same amount","aerobic respiration produces substantially more ATP (often cited as around 15-19 times more)","anaerobic respiration always produces more ATP","neither process produces any ATP"],"answer":1,"exp":"Aerobic respiration produces substantially more ATP per glucose molecule than anaerobic respiration, since it fully breaks down glucose using oxygen and the electron transport chain, rather than the much less efficient fermentation pathway."},{"id":"srb112010","state":"AU","section":"sr_biology","grade":"11","topic":"Photosynthesis","difficulty":"hard","style":"standard","paper":"G11-B2","q":"What is the overall purpose of photosynthesis?","options":["to break down glucose for energy","to convert light energy into chemical energy, producing glucose from carbon dioxide and water","to produce ATP through fermentation","to absorb oxygen from the atmosphere"],"answer":1,"exp":"Photosynthesis converts light energy into chemical energy, using carbon dioxide and water to produce glucose (and oxygen as a by-product)."},{"id":"srb112011","state":"AU","section":"sr_biology","grade":"11","topic":"Photosynthesis","difficulty":"hard","style":"standard","paper":"G11-B2","q":"Which of these is the correct overall equation for photosynthesis?","options":["C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O","6CO₂ + 6H₂O + light energy → C₆H₁₂O₆ + 6O₂","6O₂ + 6H₂O → C₆H₁₂O₆ + 6CO₂","C₆H₁₂O₆ → 2C₂H₅OH + 2CO₂"],"answer":1,"exp":"Photosynthesis uses carbon dioxide, water, and light energy to produce glucose and oxygen: 6CO₂ + 6H₂O + light energy → C₆H₁₂O₆ + 6O₂."},{"id":"srb112012","state":"AU","section":"sr_biology","grade":"11","topic":"Photosynthesis","difficulty":"hard","style":"standard","paper":"G11-B2","q":"In which structure within a plant cell does photosynthesis take place?","options":["the mitochondria","the chloroplast","the nucleus","the Golgi apparatus"],"answer":1,"exp":"Photosynthesis takes place in the chloroplast, an organelle containing chlorophyll, which captures light energy."},{"id":"srb112013","state":"AU","section":"sr_biology","grade":"11","topic":"Photosynthesis","difficulty":"hard","style":"standard","paper":"G11-B2","q":"What is the role of chlorophyll in photosynthesis?","options":["chlorophyll has no real functional role","chlorophyll absorbs light energy, primarily in the red and blue wavelengths, which powers the light-dependent reactions","chlorophyll absorbs carbon dioxide directly","chlorophyll is a by-product of photosynthesis, not an active participant"],"answer":1,"exp":"Chlorophyll absorbs light energy, primarily in the red and blue wavelengths (while reflecting green light, giving plants their colour), which powers the light-dependent reactions of photosynthesis."},{"id":"srb112014","state":"AU","section":"sr_biology","grade":"11","topic":"Photosynthesis","difficulty":"hard","style":"standard","paper":"G11-B2","q":"What are the main products of the light-dependent reactions of photosynthesis?","options":["glucose and carbon dioxide","ATP, NADPH, and oxygen (as a by-product)","only carbon dioxide","water and glucose"],"answer":1,"exp":"The light-dependent reactions produce ATP and NADPH (energy carriers used in the next stage), along with oxygen as a by-product from the splitting of water molecules."},{"id":"srb112015","state":"AU","section":"sr_biology","grade":"11","topic":"Photosynthesis","difficulty":"hard","style":"standard","paper":"G11-B2","q":"Where do the light-independent reactions (the Calvin cycle) of photosynthesis take place?","options":["the thylakoid membrane","the stroma of the chloroplast","the mitochondrial matrix","the nucleus"],"answer":1,"exp":"The Calvin cycle takes place in the stroma, the fluid-filled space surrounding the thylakoids within the chloroplast."},{"id":"srb112016","state":"AU","section":"sr_biology","grade":"11","topic":"Photosynthesis","difficulty":"hard","style":"standard","paper":"G11-B2","q":"What is the main purpose of the Calvin cycle (light-independent reactions)?","options":["to absorb light energy directly","to use ATP and NADPH (produced in the light-dependent reactions) to fix carbon dioxide into glucose","to split water molecules to release oxygen","to break down glucose for energy"],"answer":1,"exp":"The Calvin cycle uses the ATP and NADPH produced during the light-dependent reactions to fix carbon dioxide, ultimately building it into glucose."},{"id":"srb112017","state":"AU","section":"sr_biology","grade":"11","topic":"Photosynthesis and Respiration","difficulty":"hard","style":"standard","paper":"G11-B2","q":"Which best describes the relationship between photosynthesis and cellular respiration, in terms of their reactants and products?","options":["they are completely unrelated processes","photosynthesis produces glucose and oxygen (using carbon dioxide and water), while cellular respiration consumes glucose and oxygen (producing carbon dioxide and water) — essentially reverse processes","both processes produce identical products","neither process involves glucose at all"],"answer":1,"exp":"Photosynthesis and cellular respiration are essentially reverse processes: photosynthesis produces glucose and oxygen from carbon dioxide and water, while cellular respiration consumes glucose and oxygen, producing carbon dioxide and water."},{"id":"srb112018","state":"AU","section":"sr_biology","grade":"11","topic":"Photosynthesis and Respiration","difficulty":"hard","style":"standard","paper":"G11-B2","q":"Why do plants need to carry out both photosynthesis and cellular respiration, rather than just photosynthesis alone?","options":["plants do not actually carry out cellular respiration","plants need cellular respiration to convert the glucose produced by photosynthesis into usable ATP for their own cellular processes","cellular respiration produces the carbon dioxide plants need for photosynthesis directly","this combination has no functional purpose"],"answer":1,"exp":"Plants need cellular respiration to convert the glucose produced by photosynthesis into ATP, the usable form of energy required for their own cellular processes, just like other living organisms."},{"id":"srb112019","state":"AU","section":"sr_biology","grade":"11","topic":"Photosynthesis — Limiting Factors","difficulty":"hard","style":"standard","paper":"G11-B2","q":"How does increasing light intensity typically affect the rate of photosynthesis, up to a certain point?","options":["increasing light intensity always decreases the rate of photosynthesis","increasing light intensity generally increases the rate of photosynthesis, up until another factor (like CO₂ concentration) becomes limiting","light intensity has no effect on photosynthesis rate","photosynthesis rate is always constant regardless of light intensity"],"answer":1,"exp":"Increasing light intensity generally increases the rate of photosynthesis, since light-dependent reactions can proceed faster, until another factor (such as carbon dioxide concentration or temperature) becomes the limiting factor instead."},{"id":"srb112020","state":"AU","section":"sr_biology","grade":"11","topic":"Photosynthesis — Limiting Factors","difficulty":"hard","style":"standard","paper":"G11-B2","q":"What is a 'limiting factor' in the context of photosynthesis?","options":["a factor that has no effect on the rate of photosynthesis","whichever environmental factor (light, CO₂, temperature) is in shortest supply relative to the others, restricting the overall rate of photosynthesis at a given time","a structure within the chloroplast","a type of pigment"],"answer":1,"exp":"A limiting factor is whichever environmental factor (such as light intensity, carbon dioxide concentration, or temperature) is in shortest supply relative to the others at a given time, restricting the overall rate of photosynthesis regardless of how abundant the other factors are."},{"id":"srb112021","state":"AU","section":"sr_biology","grade":"11","topic":"Photosynthesis — Limiting Factors","difficulty":"hard","style":"standard","paper":"G11-B2","q":"Why does photosynthesis rate typically decrease at very high temperatures, despite generally increasing with moderate warming?","options":["temperature never affects photosynthesis rate","excessively high temperatures can denature the enzymes involved in the Calvin cycle, reducing their effectiveness","high temperatures always increase photosynthesis rate without limit","plants stop needing carbon dioxide at high temperatures"],"answer":1,"exp":"Excessively high temperatures can denature the enzymes involved in the Calvin cycle, altering their shape and reducing their effectiveness, which decreases the overall rate of photosynthesis despite the general trend of increased rates with moderate warming."},{"id":"srb112022","state":"AU","section":"sr_biology","grade":"11","topic":"Photosynthesis","difficulty":"hard","style":"standard","paper":"G11-B2","q":"Which best describes the overall energy transformation occurring during photosynthesis?","options":["chemical energy is transformed into light energy","light energy is transformed into chemical energy, stored within glucose molecules","mechanical energy is transformed into chemical energy","no energy transformation actually occurs during photosynthesis"],"answer":1,"exp":"Photosynthesis transforms light energy into chemical energy, which becomes stored within the bonds of glucose molecules produced during the process."},{"id":"srb112023","state":"AU","section":"sr_biology","grade":"11","topic":"Cellular Respiration","difficulty":"hard","style":"standard","paper":"G11-B2","q":"Which best describes why aerobic respiration is generally more efficient at producing ATP than anaerobic respiration?","options":["aerobic respiration fully breaks down glucose using the Krebs cycle and electron transport chain, extracting far more energy than the partial breakdown occurring in anaerobic respiration","anaerobic respiration always produces more ATP per glucose molecule","aerobic and anaerobic respiration are equally efficient","aerobic respiration does not actually require glucose"],"answer":0,"exp":"Aerobic respiration fully breaks down glucose using the Krebs cycle and electron transport chain, extracting far more of the energy stored within glucose than the much more limited, partial breakdown occurring in anaerobic respiration."},{"id":"srb112024","state":"AU","section":"sr_biology","grade":"11","topic":"Photosynthesis and Respiration","difficulty":"hard","style":"standard","paper":"G11-B2","q":"Which best describes why plants are described as 'autotrophs', while animals are described as 'heterotrophs'?","options":["autotrophs and heterotrophs mean the same thing","autotrophs can produce their own food (e.g. through photosynthesis), while heterotrophs must obtain food by consuming other organisms","heterotrophs can produce their own food, while autotrophs cannot","this distinction has no connection to how organisms obtain energy"],"answer":1,"exp":"Autotrophs, like plants, can produce their own food through processes like photosynthesis, while heterotrophs, like animals, must obtain food (and the energy it contains) by consuming other organisms."},{"id":"srb112025","state":"AU","section":"sr_biology","grade":"11","topic":"Cellular Respiration","difficulty":"hard","style":"standard","paper":"G11-B2","q":"Which best describes the role of NADH and FADH₂ in cellular respiration?","options":["they are waste products with no further function","they act as electron carriers, transporting high-energy electrons from earlier stages to the electron transport chain","they are the final products of cellular respiration","they are only involved in photosynthesis"],"answer":1,"exp":"NADH and FADH₂ act as electron carriers, transporting high-energy electrons gathered during glycolysis and the Krebs cycle to the electron transport chain, where their energy is used to generate large amounts of ATP."},{"id":"srb113001","state":"AU","section":"sr_biology","grade":"11","topic":"Homeostasis","difficulty":"hard","style":"standard","paper":"G11-B3","q":"What is 'homeostasis'?","options":["a single, one-off bodily reaction","the maintenance of a stable internal environment despite changes in external conditions","a type of cell division","a disease affecting the nervous system"],"answer":1,"exp":"Homeostasis is the ongoing maintenance of a stable internal environment (such as temperature, pH, or blood glucose) despite changes in external conditions."},{"id":"srb113002","state":"AU","section":"sr_biology","grade":"11","topic":"Homeostasis","difficulty":"hard","style":"standard","paper":"G11-B3","q":"What is a 'negative feedback loop' in the context of homeostasis?","options":["a mechanism that amplifies a change further away from a set point","a mechanism that detects a change and triggers a response to counteract it, returning the system toward its set point","a mechanism that always increases body temperature","a mechanism unrelated to homeostasis"],"answer":1,"exp":"A negative feedback loop detects a deviation from a set point and triggers a response that counteracts the change, returning the system back toward its normal range."},{"id":"srb113003","state":"AU","section":"sr_biology","grade":"11","topic":"Homeostasis","difficulty":"hard","style":"standard","paper":"G11-B3","q":"Which organ plays a central role in regulating blood glucose levels through insulin and glucagon?","options":["the liver and pancreas","the lungs","the kidneys alone","the skin"],"answer":0,"exp":"The pancreas releases insulin and glucagon to regulate blood glucose levels, while the liver stores and releases glucose (as glycogen) in response to these hormones."},{"id":"srb113004","state":"AU","section":"sr_biology","grade":"11","topic":"Homeostasis","difficulty":"hard","style":"standard","paper":"G11-B3","q":"What happens when blood glucose levels rise after a meal?","options":["the pancreas releases glucagon to raise glucose further","the pancreas releases insulin, which promotes glucose uptake by cells and storage as glycogen","the liver releases more glucose into the blood","nothing happens to regulate glucose levels"],"answer":1,"exp":"When blood glucose rises, the pancreas releases insulin, which promotes glucose uptake by cells and its storage as glycogen, lowering blood glucose back toward normal."},{"id":"srb113005","state":"AU","section":"sr_biology","grade":"11","topic":"Homeostasis","difficulty":"hard","style":"standard","paper":"G11-B3","q":"What happens when blood glucose levels fall too low?","options":["the pancreas releases insulin to lower it further","the pancreas releases glucagon, which stimulates the liver to break down glycogen and release glucose into the blood","the kidneys filter out all remaining glucose","the body stops needing glucose entirely"],"answer":1,"exp":"When blood glucose falls too low, the pancreas releases glucagon, which stimulates the liver to break down stored glycogen and release glucose back into the blood."},{"id":"srb113006","state":"AU","section":"sr_biology","grade":"11","topic":"Homeostasis","difficulty":"hard","style":"standard","paper":"G11-B3","q":"Which structure in the brain acts as the body's main thermoregulatory centre?","options":["the cerebellum","the hypothalamus","the medulla oblongata only","the pituitary gland"],"answer":1,"exp":"The hypothalamus acts as the body's main thermoregulatory centre, detecting changes in blood temperature and triggering responses to maintain a stable body temperature."},{"id":"srb113007","state":"AU","section":"sr_biology","grade":"11","topic":"Homeostasis","difficulty":"hard","style":"standard","paper":"G11-B3","q":"Which response would the body trigger to cool down when body temperature rises too high?","options":["shivering and vasoconstriction","sweating and vasodilation of skin blood vessels","increased metabolic rate only","reduced blood flow to the skin"],"answer":1,"exp":"To cool down, the body triggers sweating (which cools through evaporation) and vasodilation of skin blood vessels (increasing blood flow to the skin, allowing more heat to radiate away)."},{"id":"srb113008","state":"AU","section":"sr_biology","grade":"11","topic":"Immune System","difficulty":"hard","style":"standard","paper":"G11-B3","q":"What is the first line of defence against pathogens entering the body?","options":["white blood cells producing antibodies","physical and chemical barriers, such as skin and stomach acid","the inflammatory response","memory cells"],"answer":1,"exp":"The first line of defence consists of physical and chemical barriers, such as the skin, mucous membranes, and stomach acid, which prevent pathogens from entering the body in the first place."},{"id":"srb113009","state":"AU","section":"sr_biology","grade":"11","topic":"Immune System","difficulty":"hard","style":"standard","paper":"G11-B3","q":"What is the role of phagocytes in the immune system?","options":["they produce antibodies specific to a pathogen","they engulf and digest pathogens and debris through phagocytosis, as part of the non-specific immune response","they store genetic information","they regulate blood glucose"],"answer":1,"exp":"Phagocytes engulf and digest pathogens and cellular debris through a process called phagocytosis, forming part of the body's non-specific (innate) immune response."},{"id":"srb113010","state":"AU","section":"sr_biology","grade":"11","topic":"Immune System","difficulty":"hard","style":"standard","paper":"G11-B3","q":"What is the difference between the innate (non-specific) and adaptive (specific) immune responses?","options":["they are exactly the same","the innate response acts quickly against any pathogen in a general way, while the adaptive response is slower but targets specific pathogens, also forming memory","the adaptive response always acts first","the innate response only occurs in adults"],"answer":1,"exp":"The innate immune response acts quickly and non-specifically against any pathogen, while the adaptive immune response is slower to develop but targets specific pathogens precisely, and also forms immunological memory."},{"id":"srb113011","state":"AU","section":"sr_biology","grade":"11","topic":"Immune System","difficulty":"hard","style":"standard","paper":"G11-B3","q":"What is an 'antigen'?","options":["a type of antibody","a molecule, often on the surface of a pathogen, that can trigger an immune response","a white blood cell","a hormone involved in homeostasis"],"answer":1,"exp":"An antigen is a molecule, often found on the surface of a pathogen, that the immune system recognises as foreign, triggering an immune response."},{"id":"srb113012","state":"AU","section":"sr_biology","grade":"11","topic":"Immune System","difficulty":"hard","style":"standard","paper":"G11-B3","q":"What is the role of B lymphocytes (B cells) in the adaptive immune response?","options":["they directly destroy infected cells only","they produce antibodies specific to a particular antigen","they regulate body temperature","they form part of the skin barrier"],"answer":1,"exp":"B lymphocytes (B cells) produce antibodies specific to a particular antigen, which can bind to and help neutralise or mark pathogens for destruction."},{"id":"srb113013","state":"AU","section":"sr_biology","grade":"11","topic":"Immune System","difficulty":"hard","style":"standard","paper":"G11-B3","q":"What is the role of T lymphocytes (T cells) in the adaptive immune response?","options":["T cells have several roles, including directly destroying infected cells (cytotoxic T cells) and helping coordinate the immune response (helper T cells)","T cells only produce antibodies","T cells are not part of the immune system","T cells only exist in the skin"],"answer":0,"exp":"T lymphocytes have several important roles, including cytotoxic T cells that directly destroy infected cells, and helper T cells that coordinate and support other parts of the immune response."},{"id":"srb113014","state":"AU","section":"sr_biology","grade":"11","topic":"Immune System","difficulty":"hard","style":"standard","paper":"G11-B3","q":"What is 'immunological memory', and why is it important?","options":["memory cells allow a faster, stronger immune response upon a second exposure to the same antigen, which is the basis for how vaccines provide long-term protection","memory cells have no real function","immunological memory only lasts a few hours","memory cells destroy the body's own healthy cells"],"answer":0,"exp":"Immunological memory, provided by memory B and T cells, allows for a faster and stronger immune response upon a second exposure to the same antigen — this is the underlying basis for how vaccines provide long-term protection."},{"id":"srb113015","state":"AU","section":"sr_biology","grade":"11","topic":"Immune System","difficulty":"hard","style":"standard","paper":"G11-B3","q":"How does a vaccine typically work to provide immunity?","options":["it introduces a weakened, inactivated, or partial form of a pathogen (or its antigens), prompting the immune system to develop memory cells without causing full-blown disease","it directly destroys all pathogens in the body immediately","it permanently disables the immune system","it has no real interaction with the immune system"],"answer":0,"exp":"A vaccine introduces a weakened, inactivated, or partial form of a pathogen (or its antigens), prompting the immune system to develop memory cells, providing future protection without causing full-blown disease."},{"id":"srb113016","state":"AU","section":"sr_biology","grade":"11","topic":"Immune System","difficulty":"hard","style":"standard","paper":"G11-B3","q":"What is an 'autoimmune disease'?","options":["a disease caused entirely by external pathogens","a condition in which the immune system mistakenly attacks the body's own healthy cells or tissues","a disease that only affects the skin","a disease with no connection to the immune system"],"answer":1,"exp":"An autoimmune disease occurs when the immune system mistakenly identifies the body's own healthy cells or tissues as foreign, and attacks them."},{"id":"srb113017","state":"AU","section":"sr_biology","grade":"11","topic":"Homeostasis","difficulty":"hard","style":"standard","paper":"G11-B3","q":"What is the role of the kidneys in homeostasis?","options":["regulating blood glucose only","regulating water balance and removing metabolic waste products from the blood, maintaining a stable internal fluid environment","producing antibodies","regulating body temperature only"],"answer":1,"exp":"The kidneys play a key role in homeostasis by regulating water balance and removing metabolic waste products from the blood, helping maintain a stable internal fluid environment."},{"id":"srb113018","state":"AU","section":"sr_biology","grade":"11","topic":"Homeostasis","difficulty":"hard","style":"standard","paper":"G11-B3","q":"What is 'osmoregulation'?","options":["the regulation of body temperature","the regulation of water and solute balance within the body","the regulation of blood sugar levels","a process unrelated to homeostasis"],"answer":1,"exp":"Osmoregulation is the regulation of water and solute balance within the body, helping maintain stable internal fluid concentrations."},{"id":"srb113019","state":"AU","section":"sr_biology","grade":"11","topic":"Homeostasis","difficulty":"hard","style":"standard","paper":"G11-B3","q":"Which hormone, released by the pituitary gland, helps the kidneys reabsorb more water when the body is dehydrated?","options":["insulin","antidiuretic hormone (ADH)","glucagon","adrenaline"],"answer":1,"exp":"Antidiuretic hormone (ADH), released by the pituitary gland, signals the kidneys to reabsorb more water, reducing urine output and helping conserve water when the body is dehydrated."},{"id":"srb113020","state":"AU","section":"sr_biology","grade":"11","topic":"Homeostasis","difficulty":"hard","style":"standard","paper":"G11-B3","q":"Why is maintaining a stable internal body temperature important for enzyme function?","options":["temperature has no effect on enzyme function","enzymes have an optimal temperature range, and significant deviations can reduce their effectiveness or cause denaturation","enzymes work better at any extreme temperature","this has no biological significance"],"answer":1,"exp":"Enzymes have an optimal temperature range for effective function, and significant deviations from this range can reduce their effectiveness or cause denaturation, disrupting essential biochemical reactions."},{"id":"srb113021","state":"AU","section":"sr_biology","grade":"11","topic":"Immune System","difficulty":"hard","style":"standard","paper":"G11-B3","q":"What is 'inflammation', and what is its general purpose?","options":["a harmful process with no biological benefit","a non-specific immune response involving increased blood flow, swelling, and immune cell recruitment to an injured or infected area, helping fight infection and begin healing","a type of allergic reaction only","a process exclusive to bacterial infections"],"answer":1,"exp":"Inflammation is a non-specific immune response involving increased blood flow, swelling, and the recruitment of immune cells to an injured or infected area, helping fight infection and initiate the healing process."},{"id":"srb113022","state":"AU","section":"sr_biology","grade":"11","topic":"Immune System","difficulty":"hard","style":"standard","paper":"G11-B3","q":"Which best describes 'active immunity'?","options":["immunity gained by directly receiving antibodies from another source","immunity gained when the body's own immune system produces antibodies, either through infection or vaccination","immunity that lasts only a few minutes","a type of immunity with no memory component"],"answer":1,"exp":"Active immunity is gained when the body's own immune system produces antibodies, either through natural infection or vaccination, and typically includes the formation of long-lasting memory cells."},{"id":"srb113023","state":"AU","section":"sr_biology","grade":"11","topic":"Immune System","difficulty":"hard","style":"standard","paper":"G11-B3","q":"Which best describes 'passive immunity'?","options":["immunity gained when the body produces its own antibodies","immunity gained by receiving ready-made antibodies from another source (such as through breast milk or an antibody injection), typically providing temporary protection","a type of immunity that always lasts a lifetime","immunity gained only through vaccination"],"answer":1,"exp":"Passive immunity is gained by receiving ready-made antibodies from another source, such as through breast milk or an antibody injection, typically providing temporary protection without the body producing its own long-lasting memory cells."},{"id":"srb113024","state":"AU","section":"sr_biology","grade":"11","topic":"Homeostasis","difficulty":"hard","style":"standard","paper":"G11-B3","q":"Which best explains why maintaining stable blood pH is important for the body?","options":["pH has no real effect on bodily function","many enzymes and biochemical processes are sensitive to pH, and significant deviations can disrupt normal cellular function","blood pH naturally varies enormously with no consequence","pH only matters in the digestive system"],"answer":1,"exp":"Many enzymes and biochemical processes are sensitive to pH, and significant deviations from the normal range can disrupt normal cellular function, which is why the body tightly regulates blood pH."},{"id":"srb113025","state":"AU","section":"sr_biology","grade":"11","topic":"Homeostasis","difficulty":"hard","style":"standard","paper":"G11-B3","q":"Which best describes the relationship between the hypothalamus and the pituitary gland in hormonal regulation?","options":["they have no functional relationship","the hypothalamus produces hormones that regulate the pituitary gland's release of its own hormones, linking the nervous and endocrine systems","the pituitary gland controls the hypothalamus exclusively","both glands perform identical functions"],"answer":1,"exp":"The hypothalamus produces hormones that regulate the pituitary gland's release of its own hormones, forming an important link between the nervous and endocrine systems in coordinating homeostasis."},{"id":"srb114001","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What is 'natural selection'?","options":["the deliberate breeding of organisms by humans","the process by which individuals with traits better suited to their environment tend to survive and reproduce more successfully, passing those traits to offspring","a process that occurs only in plants","a random process with no connection to survival or reproduction"],"answer":1,"exp":"Natural selection is the process by which individuals with traits better suited to their environment tend to survive and reproduce more successfully, gradually increasing the frequency of those advantageous traits within a population."},{"id":"srb114002","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What is required for natural selection to occur within a population?","options":["a population with absolutely no variation","heritable variation among individuals, a selective pressure favouring certain traits, and differential reproductive success","a population that never reproduces","an environment that never changes"],"answer":1,"exp":"Natural selection requires heritable variation among individuals, a selective pressure (such as predation, disease, or competition) favouring certain traits, and differential reproductive success based on those traits."},{"id":"srb114003","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What is a 'mutation', and what role can it play in evolution?","options":["a deliberate change made by an organism","a random change in DNA sequence, which can introduce new genetic variation that natural selection may act upon","a process that always immediately kills an organism","a change that has no connection to evolution"],"answer":1,"exp":"A mutation is a random change in DNA sequence, which can introduce new genetic variation into a population — variation that natural selection may then act upon, favouring or disfavouring the new trait."},{"id":"srb114004","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What is 'genetic drift'?","options":["a deliberate selection process","random changes in allele frequencies within a population, which can have a particularly strong effect in small populations","a process identical to natural selection","a process that only occurs in extinct species"],"answer":1,"exp":"Genetic drift describes random changes in allele frequencies within a population, occurring purely by chance rather than selective pressure, and having a particularly strong effect in small populations."},{"id":"srb114005","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What is 'speciation'?","options":["the extinction of a species","the process by which new, distinct species arise, often due to populations becoming reproductively isolated from each other","a type of genetic mutation","a process that occurs instantly within a single generation"],"answer":1,"exp":"Speciation is the process by which new, distinct species arise, often occurring when populations become reproductively isolated from each other (such as by geographic separation) and accumulate genetic differences over many generations."},{"id":"srb114006","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What is 'allopatric speciation'?","options":["speciation occurring within a single, unified population with no separation","speciation occurring when populations become geographically separated, preventing interbreeding and allowing them to diverge genetically over time","a process that only occurs in plants","speciation that always happens within a single generation"],"answer":1,"exp":"Allopatric speciation occurs when populations become geographically separated (for example, by a mountain range or body of water), preventing interbreeding and allowing the separated populations to diverge genetically over time."},{"id":"srb114007","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What evidence does the fossil record provide for evolution?","options":["fossils provide no useful evidence for evolution","fossils show a chronological record of changes in organisms over time, including transitional forms linking different groups","fossils only show that all species have remained completely unchanged","fossils can only be found in rocks younger than 1000 years"],"answer":1,"exp":"The fossil record shows a chronological record of changes in organisms over geological time, including transitional forms that provide evidence for evolutionary relationships between different groups."},{"id":"srb114008","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What does comparative anatomy (such as homologous structures) suggest about evolution?","options":["homologous structures provide no evidence for evolutionary relationships","similar underlying structures in different species (such as the forelimb bones of mammals) suggest descent from a common ancestor, even when the structures serve different functions","homologous structures always serve identical functions across species","comparative anatomy is unrelated to the study of evolution"],"answer":1,"exp":"Homologous structures — similar underlying anatomical features in different species, even when adapted for different functions (such as a bat's wing and a human's arm) — suggest descent from a common ancestor."},{"id":"srb114009","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What does molecular evidence (such as DNA sequence comparison) contribute to our understanding of evolutionary relationships?","options":["molecular evidence has no connection to evolutionary study","greater similarity in DNA sequences between species generally suggests a more recent common ancestor and closer evolutionary relationship","DNA sequences are always identical between unrelated species","molecular evidence contradicts all other evidence for evolution"],"answer":1,"exp":"Greater similarity in DNA sequences between species generally suggests a more recent common ancestor and a closer evolutionary relationship, providing a powerful additional source of evidence alongside fossils and comparative anatomy."},{"id":"srb114010","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What is 'convergent evolution'?","options":["closely related species independently evolving identical traits","unrelated species independently evolving similar traits or structures due to facing similar environmental pressures","the only mechanism by which evolution can occur","a process unrelated to natural selection"],"answer":1,"exp":"Convergent evolution occurs when unrelated species independently evolve similar traits or structures, typically because they face similar environmental pressures or occupy similar ecological niches."},{"id":"srb114011","state":"AU","section":"sr_biology","grade":"11","topic":"Biodiversity","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What is 'biodiversity'?","options":["the total mass of all organisms in an area","the variety of life in a particular ecosystem or on Earth as a whole, including genetic, species, and ecosystem diversity","a measure of an ecosystem's temperature range","a term referring only to plant species"],"answer":1,"exp":"Biodiversity refers to the variety of life in a particular ecosystem or on Earth as a whole, encompassing genetic diversity (within species), species diversity, and ecosystem diversity."},{"id":"srb114012","state":"AU","section":"sr_biology","grade":"11","topic":"Biodiversity","difficulty":"hard","style":"standard","paper":"G11-B4","q":"Why is biodiversity generally considered important for ecosystem stability?","options":["biodiversity has no real connection to ecosystem stability","greater biodiversity often provides more resilience against environmental changes and disturbances, since a wider variety of species can fill important ecological roles","ecosystems with low biodiversity are always more stable","biodiversity only matters for aesthetic reasons"],"answer":1,"exp":"Greater biodiversity often provides more resilience against environmental changes and disturbances, since a wider variety of species can fill important ecological roles, reducing the risk that the loss of one species severely disrupts the whole ecosystem."},{"id":"srb114013","state":"AU","section":"sr_biology","grade":"11","topic":"Biodiversity","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What is a 'keystone species'?","options":["a species that has no real impact on its ecosystem","a species whose presence has a disproportionately large effect on the structure and function of its ecosystem, relative to its abundance","a species found only in fossils","a species that exists in every single ecosystem on Earth"],"answer":1,"exp":"A keystone species has a disproportionately large effect on the structure and function of its ecosystem, relative to its actual abundance — its removal can cause significant, cascading changes throughout the ecosystem."},{"id":"srb114014","state":"AU","section":"sr_biology","grade":"11","topic":"Biodiversity","difficulty":"hard","style":"standard","paper":"G11-B4","q":"Which of these is a major human-driven cause of biodiversity loss?","options":["natural background extinction rates alone","habitat destruction, such as deforestation and land clearing for agriculture or development","biodiversity loss never occurs due to human activity","a complete absence of any environmental change"],"answer":1,"exp":"Habitat destruction, such as deforestation and land clearing for agriculture or development, is a major human-driven cause of biodiversity loss, removing the living space many species depend on."},{"id":"srb114015","state":"AU","section":"sr_biology","grade":"11","topic":"Biodiversity","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What is an 'invasive species'?","options":["a native species that has always lived in an ecosystem","a non-native species introduced to an ecosystem, which can disrupt the existing balance, often outcompeting native species","a species that is always beneficial to its new ecosystem","a term with no real ecological significance"],"answer":1,"exp":"An invasive species is a non-native species introduced to a new ecosystem, which can disrupt the existing ecological balance, often by outcompeting native species for resources or introducing new diseases."},{"id":"srb114016","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution and Biodiversity","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What is a 'population bottleneck', and how can it affect a species' genetic diversity?","options":["a population bottleneck has no effect on genetic diversity","a sharp reduction in population size, which can significantly reduce genetic diversity, since fewer surviving individuals carry a smaller range of alleles","a process that always increases genetic diversity","a term unrelated to population genetics"],"answer":1,"exp":"A population bottleneck is a sharp reduction in population size (often due to a disaster or habitat loss), which can significantly reduce genetic diversity, since the smaller surviving population carries only a fraction of the original range of alleles."},{"id":"srb114017","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution and Biodiversity","difficulty":"hard","style":"standard","paper":"G11-B4","q":"Why might reduced genetic diversity make a species more vulnerable to extinction?","options":["genetic diversity has no connection to a species' survival prospects","lower genetic diversity reduces the likelihood that some individuals carry traits that could help the population survive new environmental challenges, such as disease or climate change","reduced genetic diversity always makes a species stronger","species with low genetic diversity are immune to disease"],"answer":1,"exp":"Lower genetic diversity reduces the likelihood that at least some individuals carry traits that could help the population survive new environmental challenges, such as a new disease or a changing climate, making the species more vulnerable overall."},{"id":"srb114018","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What is 'artificial selection' (selective breeding), and how does it relate to natural selection?","options":["artificial selection is identical to natural selection in every way","artificial selection involves humans deliberately choosing which organisms breed based on desired traits, applying a similar underlying principle to natural selection but with human-directed pressure rather than natural pressures","artificial selection has no connection to natural selection at all","artificial selection can only occur in laboratory settings"],"answer":1,"exp":"Artificial selection involves humans deliberately choosing which organisms breed based on desired traits (such as crop yield or dog temperament), applying a similar underlying principle to natural selection, but driven by human-directed pressure rather than natural environmental pressures."},{"id":"srb114019","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What is the 'theory of evolution by natural selection' most closely associated with, historically?","options":["Gregor Mendel's work on genetics alone","Charles Darwin's observations and theoretical work, particularly following his voyage on the HMS Beagle","a theory with no specific historical origin","a purely modern theory with no historical roots"],"answer":1,"exp":"The theory of evolution by natural selection is most closely associated with Charles Darwin's observations and theoretical work, particularly following his extensive observations during the voyage of the HMS Beagle."},{"id":"srb114020","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What is 'adaptive radiation'?","options":["a process where a single species remains completely unchanged over millions of years","the relatively rapid diversification of a single ancestral species into multiple new species, often adapted to different ecological niches","a process exclusive to bacteria","a term with no connection to evolutionary biology"],"answer":1,"exp":"Adaptive radiation describes the relatively rapid diversification of a single ancestral species into multiple new species, each often adapted to different ecological niches — a classic example being the finches Darwin observed in the Galápagos Islands."},{"id":"srb114021","state":"AU","section":"sr_biology","grade":"11","topic":"Biodiversity","difficulty":"hard","style":"standard","paper":"G11-B4","q":"What does it mean for a species to be classified as 'endangered'?","options":["the species has already become extinct","the species faces a high risk of extinction in the near future, often due to declining population size and threats such as habitat loss","the species has an extremely stable, growing population","this classification has no real conservation significance"],"answer":1,"exp":"An endangered classification indicates a species faces a high risk of extinction in the near future, often due to a declining population size and ongoing threats such as habitat loss, hunting, or disease."},{"id":"srb114022","state":"AU","section":"sr_biology","grade":"11","topic":"Biodiversity","difficulty":"hard","style":"standard","paper":"G11-B4","q":"Why might conservation efforts focus specifically on protecting keystone species within an ecosystem?","options":["keystone species have no particular conservation priority","protecting a keystone species can have a disproportionately large positive effect on the overall health and stability of the ecosystem, given its outsized ecological role","keystone species are always the most numerous in an ecosystem","conservation efforts never prioritise specific species"],"answer":1,"exp":"Protecting a keystone species can have a disproportionately large positive effect on the overall health and stability of an ecosystem, given its outsized ecological role relative to its abundance."},{"id":"srb114023","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution and Biodiversity","difficulty":"hard","style":"standard","paper":"G11-B4","q":"Which best describes the relationship between evolution and the long-term sustainability of a population's gene pool?","options":["evolution has no connection to long-term population sustainability","ongoing genetic variation, partly generated through mutation and recombination, provides the raw material natural selection can act upon, helping populations adapt to future environmental changes","a population's gene pool never changes over time","genetic variation always harms a population's survival prospects"],"answer":1,"exp":"Ongoing genetic variation, generated partly through mutation and genetic recombination, provides the raw material natural selection can act upon, helping populations adapt to future environmental changes and supporting long-term sustainability."},{"id":"srb114024","state":"AU","section":"sr_biology","grade":"11","topic":"Biodiversity","difficulty":"hard","style":"standard","paper":"G11-B4","q":"Why do conservation biologists often emphasise protecting genetically diverse populations, rather than just maximising total population numbers?","options":["genetic diversity has no real conservation value compared to raw population size","a genetically diverse population has a greater capacity to adapt to future environmental changes, even if its total numbers are smaller than a less diverse population","maximising population numbers always ensures long-term survival regardless of genetic diversity","genetic diversity and population size are exactly the same consideration"],"answer":1,"exp":"A genetically diverse population has a greater capacity to adapt to future environmental changes, even if its total numbers are smaller than a less diverse population — diversity provides a kind of long-term insurance against new and unpredictable threats."},{"id":"srb114025","state":"AU","section":"sr_biology","grade":"11","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G11-B4","q":"Which best describes 'sympatric speciation', as distinct from allopatric speciation?","options":["speciation that requires complete geographic separation","speciation occurring without geographic separation, through other reproductive barriers arising within the same area","a process identical to allopatric speciation","a term with no real distinction from allopatric speciation"],"answer":1,"exp":"Sympatric speciation occurs without geographic separation, through other reproductive barriers (such as behavioural or genetic differences) arising within populations that continue to share the same geographic area."},{"id":"srb121001","state":"AU","section":"sr_biology","grade":"12","topic":"DNA Structure","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is the structure of DNA often described as?","options":["a single straight chain","a double helix, formed by two strands twisted around each other","a flat, two-dimensional sheet","a perfect sphere"],"answer":1,"exp":"DNA is structured as a double helix, formed by two complementary strands twisted around each other, held together by hydrogen bonds between base pairs."},{"id":"srb121002","state":"AU","section":"sr_biology","grade":"12","topic":"DNA Structure","difficulty":"hard","style":"standard","paper":"G12-B1","q":"Which base pairs with adenine (A) in DNA?","options":["guanine (G)","cytosine (C)","thymine (T)","another adenine (A)"],"answer":2,"exp":"Adenine (A) pairs with thymine (T) through hydrogen bonds, one of the two specific base-pairing rules in DNA."},{"id":"srb121003","state":"AU","section":"sr_biology","grade":"12","topic":"DNA Structure","difficulty":"hard","style":"standard","paper":"G12-B1","q":"Which base pairs with guanine (G) in DNA?","options":["adenine (A)","cytosine (C)","thymine (T)","another guanine (G)"],"answer":1,"exp":"Guanine (G) pairs with cytosine (C) through hydrogen bonds, the other of the two specific base-pairing rules in DNA."},{"id":"srb121004","state":"AU","section":"sr_biology","grade":"12","topic":"DNA Replication","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is the role of the enzyme DNA helicase in DNA replication?","options":["it joins new nucleotides together to form a new strand","it unwinds and separates the two strands of the DNA double helix, exposing the bases for replication","it removes RNA primers","it translates mRNA into protein"],"answer":1,"exp":"DNA helicase unwinds and separates the two strands of the DNA double helix, exposing the bases so that each strand can serve as a template for replication."},{"id":"srb121005","state":"AU","section":"sr_biology","grade":"12","topic":"DNA Replication","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is the role of the enzyme DNA polymerase in DNA replication?","options":["it unwinds the DNA double helix","it adds new complementary nucleotides to a growing DNA strand, using the original strand as a template","it translates mRNA into protein","it breaks down old DNA strands permanently"],"answer":1,"exp":"DNA polymerase adds new complementary nucleotides to a growing DNA strand, using the original (template) strand to determine the correct sequence."},{"id":"srb121006","state":"AU","section":"sr_biology","grade":"12","topic":"DNA Replication","difficulty":"hard","style":"standard","paper":"G12-B1","q":"Why is DNA replication described as 'semi-conservative'?","options":["the entire original DNA molecule is destroyed during replication","each new DNA molecule consists of one original (parent) strand and one newly synthesised strand","both new DNA molecules consist entirely of newly synthesised strands","DNA replication does not actually conserve any part of the original molecule"],"answer":1,"exp":"DNA replication is semi-conservative because each new DNA molecule consists of one original (parent) strand and one newly synthesised strand, conserving half of the original molecule in each copy."},{"id":"srb121007","state":"AU","section":"sr_biology","grade":"12","topic":"Protein Synthesis","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is 'transcription' in the context of gene expression?","options":["the process of copying DNA to make more DNA","the process of synthesising an mRNA molecule from a DNA template","the process of joining amino acids to form a protein","a process that occurs only in prokaryotic cells"],"answer":1,"exp":"Transcription is the process of synthesising an mRNA molecule from a DNA template, occurring within the nucleus in eukaryotic cells."},{"id":"srb121008","state":"AU","section":"sr_biology","grade":"12","topic":"Protein Synthesis","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is 'translation' in the context of gene expression?","options":["the process of copying DNA into mRNA","the process of synthesising a protein from an mRNA template, with the help of ribosomes","a process that occurs within the nucleus","a process unrelated to protein synthesis"],"answer":1,"exp":"Translation is the process of synthesising a protein from an mRNA template, occurring at ribosomes, where the mRNA sequence is 'translated' into a specific sequence of amino acids."},{"id":"srb121009","state":"AU","section":"sr_biology","grade":"12","topic":"Protein Synthesis","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is a 'codon' in the context of protein synthesis?","options":["a single nucleotide","a sequence of three nucleotides in mRNA that codes for a specific amino acid (or a stop signal)","an entire gene","a type of protein"],"answer":1,"exp":"A codon is a sequence of three nucleotides in mRNA that codes for a specific amino acid, or signals the start or stop of protein synthesis."},{"id":"srb121010","state":"AU","section":"sr_biology","grade":"12","topic":"Protein Synthesis","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is the role of tRNA (transfer RNA) during translation?","options":["tRNA carries the genetic code from the nucleus to the cytoplasm","tRNA carries specific amino acids to the ribosome and pairs with the corresponding codon on the mRNA","tRNA replicates DNA","tRNA breaks down old proteins"],"answer":1,"exp":"tRNA carries specific amino acids to the ribosome, with its anticodon pairing with the corresponding codon on the mRNA strand, ensuring the correct amino acid sequence is built."},{"id":"srb121011","state":"AU","section":"sr_biology","grade":"12","topic":"Mutations","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is a 'gene mutation'?","options":["a change in an organism's behaviour","a change in the nucleotide sequence of DNA, which may or may not affect the resulting protein","a process that only occurs during translation","a deliberate change made by a scientist"],"answer":1,"exp":"A gene mutation is a change in the nucleotide sequence of DNA, which may or may not affect the structure or function of the resulting protein, depending on the type and location of the mutation."},{"id":"srb121012","state":"AU","section":"sr_biology","grade":"12","topic":"Mutations","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is a 'point mutation'?","options":["a mutation affecting an entire chromosome","a mutation involving a change to a single nucleotide base in the DNA sequence","a mutation that always results in a new species","a mutation that can never affect protein structure"],"answer":1,"exp":"A point mutation involves a change to a single nucleotide base in the DNA sequence, such as a substitution of one base for another."},{"id":"srb121013","state":"AU","section":"sr_biology","grade":"12","topic":"Mutations","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is a 'frameshift mutation', and why can it have a particularly significant effect on a protein?","options":["it has no real effect on protein structure","it involves the insertion or deletion of nucleotides not in multiples of three, shifting the reading frame and altering every subsequent codon","it only ever occurs in non-coding regions of DNA","it is identical to a point mutation in its effects"],"answer":1,"exp":"A frameshift mutation involves the insertion or deletion of nucleotides not in multiples of three, which shifts the reading frame for all subsequent codons, often dramatically altering the resulting protein."},{"id":"srb121014","state":"AU","section":"sr_biology","grade":"12","topic":"Gene Expression","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is 'gene expression regulation', broadly speaking?","options":["a process with no real biological significance","the various mechanisms a cell uses to control which genes are transcribed and translated, and to what extent, allowing different cell types to perform different functions","a process that occurs identically in every single cell of an organism, with no variation","a term referring only to mutations"],"answer":1,"exp":"Gene expression regulation refers to the various mechanisms a cell uses to control which genes are transcribed and translated, and to what extent — allowing different cell types within the same organism to perform very different specialised functions, despite sharing identical DNA."},{"id":"srb121015","state":"AU","section":"sr_biology","grade":"12","topic":"Gene Expression","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is an 'operon', as commonly studied in prokaryotic gene regulation?","options":["a single isolated gene with no regulatory elements","a cluster of genes, along with regulatory sequences, that are transcribed together as a single unit","a type of protein","a structure found only in eukaryotic cells"],"answer":1,"exp":"An operon is a cluster of genes, along with regulatory sequences, that are transcribed together as a single unit, allowing coordinated control of related genes — commonly studied in prokaryotic gene regulation (such as the lac operon)."},{"id":"srb121016","state":"AU","section":"sr_biology","grade":"12","topic":"Gene Expression","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is a 'promoter' region in relation to a gene?","options":["a region that codes for a specific protein","a DNA sequence where RNA polymerase binds to initiate transcription of a gene","a region exclusively involved in DNA replication","a structure found only in the cytoplasm"],"answer":1,"exp":"A promoter is a DNA sequence where RNA polymerase binds to initiate transcription of a gene, essentially acting as a 'start signal' for gene expression."},{"id":"srb121017","state":"AU","section":"sr_biology","grade":"12","topic":"Protein Synthesis","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is the central dogma of molecular biology?","options":["DNA → protein → RNA","DNA → RNA → protein, describing the general flow of genetic information","protein → DNA → RNA","RNA → DNA → protein, in that order, with no exceptions"],"answer":1,"exp":"The central dogma of molecular biology describes the general flow of genetic information: DNA is transcribed into RNA, which is then translated into protein."},{"id":"srb121018","state":"AU","section":"sr_biology","grade":"12","topic":"Gene Expression","difficulty":"hard","style":"standard","paper":"G12-B1","q":"Why are introns removed from mRNA before translation in eukaryotic cells?","options":["introns are coding sequences essential for translation and should never be removed","introns are non-coding sequences within a gene, and removing them (leaving only exons) ensures the mature mRNA contains only the necessary coding information","introns are removed during DNA replication, not mRNA processing","introns have no real biological significance"],"answer":1,"exp":"Introns are non-coding sequences within a gene. Removing them during mRNA processing (leaving only the coding exons joined together) ensures the mature mRNA contains only the necessary information for accurate protein synthesis."},{"id":"srb121019","state":"AU","section":"sr_biology","grade":"12","topic":"Gene Expression","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is 'alternative splicing', and why is it significant?","options":["a process with no real biological significance","a process by which different combinations of exons can be joined together from a single gene, allowing one gene to produce multiple different protein variants","a process that only occurs in bacteria","a synonym for DNA replication"],"answer":1,"exp":"Alternative splicing allows different combinations of exons to be joined together from a single gene, enabling one gene to produce multiple different protein variants — significantly increasing the diversity of proteins a genome can encode."},{"id":"srb121020","state":"AU","section":"sr_biology","grade":"12","topic":"Mutations","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is a 'silent mutation'?","options":["a mutation that always results in a non-functional protein","a mutation that changes the DNA sequence but does not change the resulting amino acid sequence (often due to the redundancy of the genetic code)","a mutation that occurs only in non-coding DNA","a mutation that always causes disease"],"answer":1,"exp":"A silent mutation changes the DNA sequence but does not change the resulting amino acid sequence, often because the genetic code is redundant (multiple codons can code for the same amino acid)."},{"id":"srb121021","state":"AU","section":"sr_biology","grade":"12","topic":"Protein Synthesis","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is the significance of the genetic code being described as 'universal'?","options":["the genetic code varies completely between every species","the same codons generally code for the same amino acids across almost all known organisms, suggesting a shared evolutionary origin","the genetic code only applies to human cells","universality means the genetic code can never mutate"],"answer":1,"exp":"The genetic code being largely 'universal' means the same codons generally code for the same amino acids across almost all known organisms, which is strong evidence suggesting all life shares a common evolutionary origin."},{"id":"srb121022","state":"AU","section":"sr_biology","grade":"12","topic":"Mutations","difficulty":"hard","style":"standard","paper":"G12-B1","q":"Which best describes why errors during DNA replication, if not corrected, could lead to mutations being passed on to offspring?","options":["DNA replication errors are always automatically corrected with no exceptions","uncorrected errors in the DNA sequence during replication can become permanent changes that are then copied and inherited in future cell divisions or generations","DNA replication errors never affect future generations","mutations can only arise from external chemical exposure, never replication errors"],"answer":1,"exp":"Uncorrected errors arising during DNA replication can become permanent changes (mutations) in the DNA sequence, which are then copied and potentially inherited in future cell divisions, or passed on to offspring if they occur in reproductive cells."},{"id":"srb121023","state":"AU","section":"sr_biology","grade":"12","topic":"DNA Replication","difficulty":"hard","style":"standard","paper":"G12-B1","q":"What is the role of proofreading mechanisms during DNA replication?","options":["proofreading has no real function during replication","proofreading mechanisms, including those built into DNA polymerase, detect and correct errors during replication, significantly reducing the mutation rate","proofreading mechanisms always introduce new errors","proofreading only occurs after an organism has died"],"answer":1,"exp":"Proofreading mechanisms, including those built into DNA polymerase itself, detect and correct errors during replication, significantly reducing the overall mutation rate and helping maintain genetic stability."},{"id":"srb121024","state":"AU","section":"sr_biology","grade":"12","topic":"Mutations","difficulty":"hard","style":"standard","paper":"G12-B1","q":"Which best describes why a mutation in a non-coding region of DNA might have little to no effect on an organism's phenotype?","options":["all mutations always have a significant effect on phenotype, regardless of location","non-coding regions do not directly code for proteins, so changes there may not alter any protein structure or function, though some non-coding regions do have regulatory importance","non-coding DNA does not actually exist","mutations can only occur in coding regions"],"answer":1,"exp":"Since non-coding regions do not directly code for proteins, mutations there may not alter any protein structure or function — though it's worth noting some non-coding regions do play important regulatory roles, so not all such mutations are necessarily without effect."},{"id":"srb121025","state":"AU","section":"sr_biology","grade":"12","topic":"DNA Structure","difficulty":"hard","style":"standard","paper":"G12-B1","q":"Which best describes the relationship between a gene and an allele?","options":["a gene and an allele are exactly the same thing with no distinction","a gene is a specific DNA sequence coding for a trait, while an allele is one of the possible different versions of that gene","an allele is always larger than a gene","a gene can only ever have one possible allele"],"answer":1,"exp":"A gene is a specific DNA sequence that codes for a particular trait, while an allele is one of the possible different versions of that gene (for example, different alleles of a gene might produce different eye colours)."},{"id":"srb122001","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is 'genetic engineering'?","options":["the natural process of mutation","the deliberate, direct manipulation of an organism's genetic material using biotechnology, often to introduce a specific desired trait","a process identical to natural selection","a term with no real scientific meaning"],"answer":1,"exp":"Genetic engineering is the deliberate, direct manipulation of an organism's genetic material using biotechnology techniques, often to introduce a specific desired trait, such as disease resistance in crops."},{"id":"srb122002","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is a 'restriction enzyme', and what role does it play in genetic engineering?","options":["an enzyme that builds new DNA strands","an enzyme that cuts DNA at specific recognition sequences, useful for isolating or inserting particular genes","an enzyme that translates mRNA into protein","an enzyme found only in human cells"],"answer":1,"exp":"A restriction enzyme cuts DNA at specific recognition sequences, which is useful in genetic engineering for isolating a particular gene of interest or preparing DNA for insertion into another organism."},{"id":"srb122003","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is 'recombinant DNA'?","options":["DNA that has never been altered in any way","DNA formed by combining genetic material from two different sources, often used to insert a desired gene into a host organism","a type of mutation","DNA found exclusively in bacteria"],"answer":1,"exp":"Recombinant DNA is formed by combining genetic material from two different sources, commonly used to insert a desired gene (such as one producing insulin) into a host organism like bacteria."},{"id":"srb122004","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is the purpose of a 'plasmid' in genetic engineering?","options":["plasmids have no real function in genetic engineering","a plasmid is a small, circular piece of DNA, often used as a vector to carry and insert a desired gene into a host cell","a plasmid is a type of protein","a plasmid is found only within the human nucleus"],"answer":1,"exp":"A plasmid is a small, circular piece of DNA, often found in bacteria, that can be used as a 'vector' to carry and insert a desired gene into a host cell during genetic engineering."},{"id":"srb122005","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What does PCR (polymerase chain reaction) allow scientists to do?","options":["PCR allows scientists to directly sequence an entire genome instantly","PCR allows scientists to rapidly amplify (make many copies of) a specific segment of DNA, even from a very small starting sample","PCR allows scientists to translate DNA directly into protein","PCR has no practical scientific application"],"answer":1,"exp":"PCR (polymerase chain reaction) allows scientists to rapidly amplify a specific segment of DNA, producing many copies even from a very small starting sample, which is useful for many applications including forensic analysis and diagnostic testing."},{"id":"srb122006","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is 'gel electrophoresis' commonly used for in molecular biology?","options":["amplifying DNA samples","separating DNA fragments by size, using an electric current to move them through a gel matrix","translating mRNA into protein","destroying unwanted DNA samples"],"answer":1,"exp":"Gel electrophoresis separates DNA fragments by size, using an electric current to move negatively charged DNA fragments through a gel matrix, with smaller fragments moving faster and further than larger ones."},{"id":"srb122007","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"Why do smaller DNA fragments move further through a gel during electrophoresis than larger fragments?","options":["smaller fragments are more strongly attracted to the negative electrode regardless of size","smaller fragments can move more easily through the pores of the gel matrix, allowing them to travel further in the same amount of time","larger fragments always move further than smaller ones","fragment size has no effect on movement through the gel"],"answer":1,"exp":"Smaller DNA fragments can move more easily and quickly through the pores of the gel matrix than larger fragments, allowing them to travel further within the same amount of time."},{"id":"srb122008","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is CRISPR-Cas9 primarily used for in modern biotechnology?","options":["amplifying DNA samples without any modification","precisely editing specific locations within a genome, allowing genes to be disabled, modified, or replaced","destroying all DNA within a cell","a purely theoretical technique with no practical laboratory use"],"answer":1,"exp":"CRISPR-Cas9 is primarily used for precisely editing specific locations within a genome, allowing genes to be disabled, modified, or replaced with remarkable accuracy compared to earlier genetic engineering techniques."},{"id":"srb122009","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is a 'genetically modified organism' (GMO)?","options":["an organism that has never had its genetic material altered","an organism whose genetic material has been altered using genetic engineering techniques, often to introduce a specific desired trait","a term referring only to bacteria","an organism that has undergone only natural mutation"],"answer":1,"exp":"A genetically modified organism (GMO) is one whose genetic material has been deliberately altered using genetic engineering techniques, often to introduce a specific desired trait, such as pest resistance in crops."},{"id":"srb122010","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is one commonly cited potential benefit of genetically modified crops?","options":["GMO crops always have no agricultural benefits","some GMO crops are engineered for traits like pest resistance or improved nutritional content, potentially increasing yield or addressing nutrient deficiencies","GMO crops cannot be grown anywhere in the world","GMO crops always require more water than non-modified crops"],"answer":1,"exp":"Some GMO crops are engineered for traits like pest resistance or improved nutritional content, which can potentially increase agricultural yield or help address nutrient deficiencies in certain populations."},{"id":"srb122011","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is one commonly raised concern regarding genetically modified organisms?","options":["GMOs are universally agreed to have no possible risks or concerns at all","concerns include potential ecological effects (such as gene transfer to wild relatives) and questions about long-term safety, which continue to be researched and debated","GMOs are illegal in every country","GMOs cannot be regulated by any government body"],"answer":1,"exp":"Commonly raised concerns include potential ecological effects, such as gene transfer to wild relative species, and ongoing questions about long-term safety — these remain active areas of scientific research, regulation, and public debate."},{"id":"srb122012","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is 'DNA sequencing'?","options":["the process of cutting DNA into fragments only","the process of determining the precise order of nucleotide bases within a DNA molecule","a technique used only to amplify DNA","a process identical to gel electrophoresis"],"answer":1,"exp":"DNA sequencing is the process of determining the precise order of nucleotide bases (A, T, G, C) within a DNA molecule, providing detailed genetic information."},{"id":"srb122013","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is the significance of the Human Genome Project?","options":["it had no significant scientific impact","it successfully mapped and sequenced nearly the entire human genome, providing a foundational resource for genetics and medical research","it focused exclusively on non-human organisms","it was completed without any use of DNA sequencing technology"],"answer":1,"exp":"The Human Genome Project successfully mapped and sequenced nearly the entire human genome, providing a foundational resource that has significantly advanced genetics, medical research, and our understanding of human biology."},{"id":"srb122014","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is 'gene therapy'?","options":["a purely theoretical concept with no clinical application","a medical technique that aims to treat or prevent disease by introducing, removing, or altering genetic material within a patient's cells","a technique used only to study extinct species","a synonym for vaccination"],"answer":1,"exp":"Gene therapy is a medical technique that aims to treat or prevent disease by introducing, removing, or altering genetic material within a patient's cells, targeting the underlying genetic cause of certain conditions."},{"id":"srb122015","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is one ethical consideration commonly raised regarding human gene editing technologies?","options":["there are no ethical considerations associated with human gene editing","concerns include questions about long-term safety, unintended consequences, and the ethics of making heritable changes that could affect future generations","gene editing in humans is considered entirely uncontroversial by all parties","ethical considerations apply only to non-human organisms"],"answer":1,"exp":"Concerns commonly raised about human gene editing include questions about long-term safety, unintended consequences, and the particular ethical weight of making heritable changes that could affect future generations who cannot consent to the alteration."},{"id":"srb122016","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is 'cloning' in a biological context?","options":["a process that always involves sexual reproduction","the process of producing genetically identical copies of an organism, cell, or piece of DNA","a synonym for genetic mutation","a process that can only occur naturally, never in a laboratory"],"answer":1,"exp":"Cloning is the process of producing genetically identical copies of an organism, cell, or piece of DNA, which can occur naturally (such as identical twins) or be carried out deliberately in a laboratory."},{"id":"srb122017","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is 'bioinformatics'?","options":["a field unrelated to biology or computing","the use of computational tools and methods to analyse and interpret large amounts of biological data, such as genomic sequences","a technique used only for amplifying DNA","a synonym for gel electrophoresis"],"answer":1,"exp":"Bioinformatics uses computational tools and methods to analyse and interpret large amounts of biological data, such as genomic sequences, which has become essential given the vast scale of modern genetic data."},{"id":"srb122018","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is a 'biomarker', and how is it used in medicine?","options":["a biomarker has no practical medical application","a biomarker is a measurable biological indicator (such as a specific protein or genetic marker) that can signal the presence of a disease, condition, or biological state","a biomarker refers only to a physical scar on the body","a biomarker is a synonym for a gene"],"answer":1,"exp":"A biomarker is a measurable biological indicator, such as a specific protein or genetic marker, that can signal the presence of a disease, condition, or particular biological state, often used in diagnosis or monitoring treatment."},{"id":"srb122019","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is the purpose of using a 'control' sample alongside a genetically modified sample in a biotechnology experiment?","options":["control samples serve no real scientific purpose","a control provides a baseline for comparison, helping researchers determine whether observed effects are genuinely due to the genetic modification rather than other factors","control samples are only used in chemistry experiments, never biology","a control sample must always be genetically identical to the experimental sample with no exceptions"],"answer":1,"exp":"A control sample provides a baseline for comparison, helping researchers determine whether any observed effects are genuinely due to the genetic modification being tested, rather than some other unrelated factor."},{"id":"srb122020","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is 'transgenic' technology?","options":["a technique that only works within a single species","technology involving the transfer of a gene from one species into the genome of a different species","a synonym for natural selection","a technique with no real practical application"],"answer":1,"exp":"Transgenic technology involves the transfer of a gene from one species into the genome of a different species, often used to introduce a beneficial trait not naturally present in the recipient organism."},{"id":"srb122021","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is one practical application of using bacteria as 'factories' for producing human insulin through genetic engineering?","options":["this approach has no practical medical use","genetically modified bacteria can be used to produce large quantities of human insulin cheaply and reliably, benefiting people with diabetes","bacteria cannot be genetically modified to produce human proteins","this technique was abandoned decades ago and is no longer used"],"answer":1,"exp":"Genetically modified bacteria, containing the human insulin gene, can be used to produce large quantities of human insulin cheaply and reliably — a well-established and ongoing application benefiting people with diabetes worldwide."},{"id":"srb122022","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"Which best describes why ethical and regulatory frameworks are considered important in the application of biotechnology?","options":["biotechnology requires no ethical or regulatory oversight whatsoever","such frameworks help balance the potential benefits of biotechnology against risks to safety, ecosystems, and broader societal concerns","ethical frameworks always completely prevent any biotechnology research from occurring","regulatory frameworks have no real connection to biotechnology"],"answer":1,"exp":"Ethical and regulatory frameworks help balance the potential benefits of biotechnology against risks to safety, ecosystems, and broader societal concerns, aiming to guide responsible development and application of these powerful technologies."},{"id":"srb122023","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"What is the significance of 'gene knockout' techniques in biological research?","options":["gene knockout techniques have no real research application","disabling (knocking out) a specific gene in a model organism allows researchers to study that gene's function by observing the resulting changes","gene knockout techniques always kill the organism instantly","this technique can only be applied to human cells"],"answer":1,"exp":"Gene knockout techniques disable a specific gene in a model organism, allowing researchers to study that gene's normal function by observing what changes occur in its absence."},{"id":"srb122024","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"Which best describes why model organisms (such as mice or fruit flies) are commonly used in genetic and biotechnology research?","options":["model organisms have no genetic similarity to humans","many model organisms share significant genetic and biological similarities with humans, while being easier, faster, and more ethical to study experimentally","model organisms are used purely for convenience, with no scientific justification","research on model organisms never provides any insight relevant to human biology"],"answer":1,"exp":"Many model organisms share significant genetic and biological similarities with humans, while being easier, faster, and more ethically straightforward to study experimentally, making them valuable tools for understanding processes relevant to human biology."},{"id":"srb122025","state":"AU","section":"sr_biology","grade":"12","topic":"Biotechnology","difficulty":"hard","style":"standard","paper":"G12-B2","q":"Which best describes the purpose of using a 'vector' in genetic engineering, such as a virus or plasmid?","options":["vectors have no functional role in genetic engineering","a vector is used to carry and deliver a desired piece of genetic material into a target cell or organism","a vector always destroys the gene it carries","a vector is a synonym for a restriction enzyme"],"answer":1,"exp":"A vector, such as a virus or plasmid, is used to carry and deliver a desired piece of genetic material into a target cell or organism, acting as a 'vehicle' for gene transfer."},{"id":"srb123001","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"What is a 'phylogenetic tree'?","options":["a diagram showing the geographic distribution of a species","a branching diagram representing the evolutionary relationships between different species or groups of organisms","a diagram showing only an organism's life cycle","a diagram with no scientific basis"],"answer":1,"exp":"A phylogenetic tree is a branching diagram representing the evolutionary relationships between different species or groups of organisms, showing how they are believed to have diverged from common ancestors."},{"id":"srb123002","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"In a phylogenetic tree, what does a branching point (node) typically represent?","options":["the extinction of a species","a common ancestor from which two or more descendant lineages diverged","a single mutation event","a geographic boundary"],"answer":1,"exp":"A branching point (node) in a phylogenetic tree typically represents a common ancestor from which two or more descendant lineages diverged."},{"id":"srb123003","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"What does the length of a branch typically represent in some types of phylogenetic trees?","options":["branch length never carries any meaningful information","in some trees, branch length can represent the amount of evolutionary change (such as genetic difference) or time elapsed along that lineage","branch length always represents the physical size of the organism","branch length represents the number of offspring produced"],"answer":1,"exp":"In some types of phylogenetic trees, branch length can represent the amount of evolutionary change (such as genetic difference) or the amount of time elapsed along that particular lineage."},{"id":"srb123004","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"What is a 'clade' in phylogenetics?","options":["a single individual organism","a group consisting of a common ancestor and all of its descendants","a group of unrelated species with no shared ancestry","a term unrelated to evolutionary classification"],"answer":1,"exp":"A clade is a group consisting of a common ancestor and all of its descendants, forming a complete branch of the evolutionary tree."},{"id":"srb123005","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"Which type of evidence is commonly used to construct modern phylogenetic trees?","options":["only physical appearance, with no other evidence considered","a combination of evidence, including morphological (physical) features, fossil records, and increasingly, molecular data such as DNA sequences","only fossil evidence, with molecular data never used","evidence based purely on geographic location"],"answer":1,"exp":"Modern phylogenetic trees are typically constructed using a combination of evidence, including morphological features, fossil records, and increasingly, molecular data such as DNA or protein sequences."},{"id":"srb123006","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"Why has molecular data (such as DNA sequencing) become increasingly important in constructing phylogenetic trees?","options":["molecular data provides no useful information for this purpose","molecular data can reveal genetic similarities and differences with great precision, often providing more detailed and objective evidence than morphology alone","molecular data always contradicts morphological evidence","molecular data can only be obtained from extinct species"],"answer":1,"exp":"Molecular data can reveal genetic similarities and differences with great precision, often providing more detailed and objective evidence of evolutionary relationships than relying on physical (morphological) features alone, which can sometimes be misleading due to convergent evolution."},{"id":"srb123007","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"What is 'cladistics'?","options":["a method of classification based solely on physical similarity, regardless of ancestry","a method of classification that groups organisms based on shared derived characteristics, reflecting evolutionary relationships and common ancestry","a method that ignores evolutionary relationships entirely","a synonym for natural selection"],"answer":1,"exp":"Cladistics is a method of classification that groups organisms based on shared derived characteristics, aiming to reflect actual evolutionary relationships and common ancestry, rather than simply grouping by overall physical similarity."},{"id":"srb123008","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"Why might convergent evolution complicate the construction of a phylogenetic tree based purely on physical features?","options":["convergent evolution never actually occurs in nature","unrelated species that have independently evolved similar features (due to similar environmental pressures) might be mistakenly grouped together as closely related, when they are not","convergent evolution always produces identical genetic sequences","this issue does not affect phylogenetic analysis in any way"],"answer":1,"exp":"Convergent evolution can cause unrelated species that have independently evolved similar features (due to facing similar environmental pressures) to be mistakenly grouped together as closely related based on physical similarity alone, when their actual evolutionary history is quite different."},{"id":"srb123009","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"What is meant by a species' 'common ancestor'?","options":["a living member of one of the descendant species","an ancestral population or organism from which two or more current species or lineages have descended","a hypothetical organism with no real evolutionary significance","a term referring only to the most recent generation"],"answer":1,"exp":"A common ancestor is an ancestral population or organism from which two or more current species or lineages have descended, representing the shared evolutionary origin point before divergence occurred."},{"id":"srb123010","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"Which best describes how scientists estimate when two lineages diverged from a common ancestor, using a technique sometimes called a 'molecular clock'?","options":["divergence time cannot be estimated using any scientific method","by assuming a relatively constant rate of genetic mutation accumulation over time, scientists can estimate how long ago two lineages diverged based on the degree of genetic difference between them","molecular clocks measure only the physical age of an individual organism","this technique relies entirely on fossil evidence with no genetic component"],"answer":1,"exp":"By assuming a relatively constant rate of genetic mutation accumulation over time, scientists can use a 'molecular clock' approach to estimate how long ago two lineages diverged, based on the degree of genetic difference observed between them today."},{"id":"srb123011","state":"AU","section":"sr_biology","grade":"12","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G12-B3","q":"What is the difference between 'homologous' and 'analogous' structures, in the context of evolutionary biology?","options":["these terms mean exactly the same thing","homologous structures share a common evolutionary origin (even if they now serve different functions), while analogous structures serve similar functions but evolved independently, without a shared origin","analogous structures always indicate close evolutionary relationships","homologous structures only exist in plants"],"answer":1,"exp":"Homologous structures share a common evolutionary origin, even if they now serve different functions (such as a bat's wing and a human's arm), while analogous structures serve similar functions but evolved independently, without a shared evolutionary origin (such as a bird's wing and an insect's wing)."},{"id":"srb123012","state":"AU","section":"sr_biology","grade":"12","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G12-B3","q":"Which best describes 'vestigial structures', and what do they suggest about evolutionary history?","options":["vestigial structures are fully functional structures with no evolutionary significance","vestigial structures are reduced or non-functional remnants of structures that served a purpose in an ancestral species, suggesting evolutionary change over time","vestigial structures only exist in extinct species","vestigial structures disprove the theory of evolution"],"answer":1,"exp":"Vestigial structures are reduced or non-functional remnants of structures that served a clear purpose in an ancestral species, suggesting evolutionary change over time as the original function was lost or reduced in the descendant species."},{"id":"srb123013","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"Which best describes why scientists continue to revise phylogenetic trees as new evidence (such as new genetic data) becomes available?","options":["phylogenetic trees, once published, are never revised again under any circumstances","science is an ongoing process, and phylogenetic trees represent current best estimates based on available evidence, which can be refined or revised as new data emerges","revising a phylogenetic tree means the original tree was entirely worthless","phylogenetic trees are based on opinion rather than evidence"],"answer":1,"exp":"Phylogenetic trees represent current best estimates based on available evidence, and as new data (such as additional genetic information) emerges, scientists may refine or revise these trees to better reflect the most accurate understanding of evolutionary relationships."},{"id":"srb123014","state":"AU","section":"sr_biology","grade":"12","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G12-B3","q":"What is 'co-evolution'?","options":["a process where two unrelated species evolve in complete isolation from each other","the process by which two or more species reciprocally affect each other's evolution, often through close ecological interactions such as predator-prey or pollinator relationships","a synonym for genetic drift","a process that can only occur within a single species"],"answer":1,"exp":"Co-evolution describes the process by which two or more species reciprocally affect each other's evolution, often through close ecological interactions, such as a predator and prey species, or a flower and its specific pollinator."},{"id":"srb123015","state":"AU","section":"sr_biology","grade":"12","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G12-B3","q":"Which best describes 'punctuated equilibrium' as a model of evolutionary change, as distinct from a purely gradual model?","options":["punctuated equilibrium suggests evolution always occurs at a perfectly constant, gradual rate","punctuated equilibrium suggests long periods of relative evolutionary stability punctuated by relatively rapid bursts of change, often associated with speciation events","punctuated equilibrium denies that evolution occurs at all","this model has been completely disproven with no remaining scientific relevance"],"answer":1,"exp":"Punctuated equilibrium suggests long periods of relative evolutionary stability, punctuated by relatively rapid bursts of evolutionary change, often associated with speciation events, contrasting with a purely gradual, constant-rate model of change."},{"id":"srb123016","state":"AU","section":"sr_biology","grade":"12","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G12-B3","q":"What is meant by an organism's 'fitness' in an evolutionary biology context?","options":["an organism's physical strength or athletic ability","an organism's relative reproductive success in passing on its genes to the next generation, within a particular environment","a measure of an organism's overall intelligence","a term unrelated to evolutionary theory"],"answer":1,"exp":"In evolutionary biology, 'fitness' refers to an organism's relative reproductive success in passing on its genes to the next generation within a particular environment — not necessarily related to physical strength in the everyday sense of the word."},{"id":"srb123017","state":"AU","section":"sr_biology","grade":"12","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G12-B3","q":"Which best describes why a trait that increases survival but reduces reproductive success might not become more common through natural selection?","options":["survival alone always guarantees a trait becomes more common","natural selection favours traits based on overall reproductive success (fitness), not survival alone, so a trait reducing reproduction could become less common despite improving survival","reproductive success has no real connection to natural selection","this scenario could never occur in nature"],"answer":1,"exp":"Natural selection favours traits based on overall reproductive success (fitness), not survival alone — a trait that improves survival but significantly reduces reproductive output could actually become less common over generations, since fewer offspring carrying that trait would be produced."},{"id":"srb123018","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"Which best describes how comparing the degree of similarity in a widely conserved protein (such as cytochrome c) across different species can support phylogenetic analysis?","options":["protein comparison provides no useful evolutionary information","species with more similar sequences of a highly conserved protein are generally considered more closely related, supporting molecular phylogenetic analysis","protein sequences are always identical across all species regardless of relatedness","this technique can only be applied to plants, never animals"],"answer":1,"exp":"Species with more similar sequences of a highly conserved protein, such as cytochrome c, are generally considered more closely related, providing molecular evidence that supports and refines phylogenetic analysis alongside other evidence types."},{"id":"srb123019","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"Which best describes the term 'outgroup' in phylogenetic analysis?","options":["a randomly selected species with no analytical purpose","a species included in an analysis that is known to be less closely related to the group of primary interest, used as a reference point to help determine the direction of evolutionary change","a synonym for a clade","a term referring only to extinct species"],"answer":1,"exp":"An outgroup is a species included in a phylogenetic analysis that is known to be less closely related to the group of primary interest, used as a reference point to help determine the likely direction and sequence of evolutionary change within the main group being studied."},{"id":"srb123020","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"Which best describes why DNA sequence comparisons between humans and other primates have provided strong evidence for evolutionary relationships?","options":["DNA comparisons between humans and other primates always show no meaningful similarity","significant similarities in DNA sequences between humans and other primates, especially close relatives like chimpanzees, support the conclusion of a relatively recent shared common ancestor","DNA sequence data is irrelevant to studying human evolutionary history","humans and other primates share no genetic similarities whatsoever"],"answer":1,"exp":"Significant similarities in DNA sequences between humans and other primates, especially close relatives like chimpanzees, support the conclusion of a relatively recent shared common ancestor, providing strong molecular evidence for evolutionary relationships within the primate lineage."},{"id":"srb123021","state":"AU","section":"sr_biology","grade":"12","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G12-B3","q":"Which best describes 'divergent evolution'?","options":["unrelated species independently evolving similar traits","two or more related species, descending from a common ancestor, gradually accumulating different traits over time as they adapt to different environments or pressures","a process identical to convergent evolution","a process that only occurs within a single generation"],"answer":1,"exp":"Divergent evolution describes two or more related species, descending from a common ancestor, gradually accumulating different traits over time as they adapt to different environments or selective pressures, becoming increasingly distinct from each other."},{"id":"srb123022","state":"AU","section":"sr_biology","grade":"12","topic":"Evolution","difficulty":"hard","style":"standard","paper":"G12-B3","q":"Which best describes why extinction events can have a significant long-term effect on the shape of subsequent phylogenetic trees?","options":["extinction events have no real effect on evolutionary history","a mass extinction can remove entire lineages, opening up ecological opportunities that surviving lineages may then diversify into, significantly reshaping future evolutionary patterns","extinction events always result in the exact same species re-evolving afterward","phylogenetic trees are entirely unaffected by which species survive or go extinct"],"answer":1,"exp":"A mass extinction can remove entire lineages from existence, opening up ecological opportunities (niches) that surviving lineages may then diversify into, significantly reshaping the future patterns of evolutionary diversification reflected in later phylogenetic trees."},{"id":"srb123023","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"Which best describes a 'monophyletic' group in cladistics?","options":["a group that excludes the common ancestor itself","a group consisting of a common ancestor and ALL of its descendants, with none excluded","a group consisting of unrelated species","a group that includes descendants but excludes some of them arbitrarily"],"answer":1,"exp":"A monophyletic group consists of a common ancestor and ALL of its descendants, with none excluded — this is generally considered the most evolutionarily meaningful type of grouping in cladistics."},{"id":"srb123024","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"Which best describes why scientists prefer using multiple independent lines of evidence (fossils, morphology, and molecular data) when constructing phylogenetic trees, rather than relying on just one?","options":["using multiple lines of evidence has no real benefit over using just one","combining independent lines of evidence helps cross-check conclusions, increasing confidence when different methods agree and prompting further investigation when they conflict","fossils alone are always sufficient with no need for any other evidence","molecular data always contradicts fossil and morphological evidence"],"answer":1,"exp":"Combining independent lines of evidence helps scientists cross-check their conclusions, increasing confidence in a proposed evolutionary relationship when different methods agree, and prompting further investigation when they conflict."},{"id":"srb123025","state":"AU","section":"sr_biology","grade":"12","topic":"Phylogenetics","difficulty":"hard","style":"standard","paper":"G12-B3","q":"Which best describes a 'paraphyletic' group in cladistics, as distinct from a monophyletic group?","options":["a paraphyletic group includes a common ancestor and all of its descendants with none excluded","a paraphyletic group includes a common ancestor and SOME, but not all, of its descendants — generally considered less evolutionarily informative than a monophyletic group","paraphyletic and monophyletic groups are exactly the same","a paraphyletic group never includes a common ancestor at all"],"answer":1,"exp":"A paraphyletic group includes a common ancestor and some, but not all, of its descendants (excluding one or more descendant branches) — generally considered less evolutionarily informative than a monophyletic group, which includes every descendant."},{"id":"srb124001","state":"AU","section":"sr_biology","grade":"12","topic":"Immune Response","difficulty":"hard","style":"standard","paper":"G12-B4","q":"What is the role of antigen-presenting cells in the adaptive immune response?","options":["they produce antibodies directly","they engulf pathogens and display fragments of the pathogen's antigens on their surface, helping activate T cells","they regulate body temperature","they have no real role in the immune response"],"answer":1,"exp":"Antigen-presenting cells engulf pathogens and display fragments of the pathogen's antigens on their surface, which helps activate T cells and initiate a targeted adaptive immune response."},{"id":"srb124002","state":"AU","section":"sr_biology","grade":"12","topic":"Immune Response","difficulty":"hard","style":"standard","paper":"G12-B4","q":"What is the difference between a 'primary' and 'secondary' immune response?","options":["they are identical in speed and strength","the primary response occurs upon first exposure to a pathogen and is relatively slow, while the secondary response (upon re-exposure) is faster and stronger, due to immunological memory","the secondary response always occurs before the primary response","neither response involves memory cells"],"answer":1,"exp":"The primary immune response occurs upon first exposure to a pathogen and is relatively slow to develop, while the secondary response (upon re-exposure to the same pathogen) is faster and stronger, due to the immunological memory established during the primary response."},{"id":"srb124003","state":"AU","section":"sr_biology","grade":"12","topic":"Immune Response","difficulty":"hard","style":"standard","paper":"G12-B4","q":"What is a 'monoclonal antibody'?","options":["a naturally occurring antibody with no laboratory application","a laboratory-produced antibody, identical in structure, designed to target one specific antigen with high precision","a type of pathogen","an antibody that can target any antigen non-specifically"],"answer":1,"exp":"A monoclonal antibody is a laboratory-produced antibody, identical in structure, designed to target one specific antigen with high precision — used in various medical diagnostics and treatments."},{"id":"srb124004","state":"AU","section":"sr_biology","grade":"12","topic":"Immune Response","difficulty":"hard","style":"standard","paper":"G12-B4","q":"What is one important medical application of monoclonal antibodies?","options":["monoclonal antibodies have no practical medical use","they are used in some diagnostic tests and treatments, including certain cancer therapies, by precisely targeting specific molecules on cells","they can only be used to study extinct organisms","they are used exclusively in agriculture, never medicine"],"answer":1,"exp":"Monoclonal antibodies are used in some diagnostic tests and treatments, including certain cancer therapies, by precisely targeting specific molecules present on particular cells, such as cancer cells."},{"id":"srb124005","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"What is an 'epidemic'?","options":["a disease affecting only a single individual","a widespread occurrence of a disease within a particular community or region, over a given period of time","a disease that has been completely eradicated worldwide","a synonym for a vaccine"],"answer":1,"exp":"An epidemic refers to a widespread occurrence of a disease within a particular community or region, occurring over a given period of time, beyond what would normally be expected."},{"id":"srb124006","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"What is a 'pandemic', and how does it differ from an epidemic?","options":["a pandemic and an epidemic mean exactly the same thing","a pandemic refers to a disease outbreak that has spread across multiple countries or continents, affecting a much larger geographic area than a typical epidemic","a pandemic is always less serious than an epidemic","a pandemic only refers to diseases affecting animals, not humans"],"answer":1,"exp":"A pandemic refers to a disease outbreak that has spread across multiple countries or continents, affecting a much larger geographic area than a typical localised epidemic."},{"id":"srb124007","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"What is 'herd immunity'?","options":["a type of immunity that only applies to farm animals","a form of indirect protection from infectious disease that occurs when a sufficiently large proportion of a population has become immune, reducing the spread of the disease to others","a synonym for passive immunity","a concept with no real epidemiological basis"],"answer":1,"exp":"Herd immunity is a form of indirect protection from infectious disease that occurs when a sufficiently large proportion of a population has become immune (through infection or vaccination), reducing the overall spread of the disease and indirectly protecting those who are not immune."},{"id":"srb124008","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"What is 'antibiotic resistance', and why is it a significant public health concern?","options":["antibiotic resistance has no real public health significance","antibiotic resistance occurs when bacteria evolve mechanisms to survive exposure to antibiotics that would normally kill them, making bacterial infections increasingly difficult to treat","antibiotic resistance only affects viruses, never bacteria","antibiotics always remain equally effective regardless of bacterial evolution"],"answer":1,"exp":"Antibiotic resistance occurs when bacteria evolve mechanisms to survive exposure to antibiotics that would normally kill them, making bacterial infections increasingly difficult to treat — a significant and growing public health concern worldwide."},{"id":"srb124009","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"Which best describes how natural selection drives the development of antibiotic resistance within a bacterial population?","options":["antibiotic resistance has no connection to natural selection","bacteria with a chance mutation conferring resistance survive antibiotic exposure and reproduce, while susceptible bacteria die, increasing the proportion of resistant bacteria over time","antibiotics always kill 100% of bacteria with no survivors, regardless of genetic variation","resistance develops identically and instantly in every bacterium exposed to an antibiotic"],"answer":1,"exp":"This is a direct example of natural selection: bacteria with a chance mutation conferring resistance survive antibiotic exposure and reproduce, while susceptible bacteria die, gradually increasing the proportion of resistant bacteria within the population over successive generations."},{"id":"srb124010","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"Why is overuse or misuse of antibiotics considered a contributing factor to the development of antibiotic resistance?","options":["antibiotic use has no connection to resistance development","frequent or unnecessary antibiotic exposure increases the selective pressure favouring resistant bacteria, accelerating the spread of resistance within bacterial populations","antibiotics always become less effective over time regardless of how they are used","overuse of antibiotics only affects the patient taking them, with no broader public health impact"],"answer":1,"exp":"Frequent or unnecessary antibiotic exposure increases the selective pressure favouring resistant bacteria, accelerating the spread of antibiotic resistance within bacterial populations, which can then spread between individuals and even between different bacterial species."},{"id":"srb124011","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"What is a 'zoonotic disease'?","options":["a disease that can only ever affect a single species","a disease that can be transmitted between animals and humans","a disease caused exclusively by genetic mutation","a synonym for an autoimmune disease"],"answer":1,"exp":"A zoonotic disease is one that can be transmitted between animals and humans, such as certain diseases that originate in animal populations before spreading to humans."},{"id":"srb124012","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"What is the difference between a bacterial and a viral infection, in terms of treatment?","options":["antibiotics are equally effective against both bacterial and viral infections","antibiotics are generally effective against bacterial infections but not viral infections, since viruses have a fundamentally different structure and replication mechanism","viral infections are always more easily treated than bacterial infections","bacteria and viruses are structurally and functionally identical"],"answer":1,"exp":"Antibiotics are generally effective against bacterial infections but not viral infections, since viruses have a fundamentally different structure and replication mechanism, requiring different approaches such as antiviral medications or vaccines."},{"id":"srb124013","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"What is an 'antiviral' medication, and how does it generally differ in approach from an antibiotic?","options":["antivirals and antibiotics work in exactly the same way","antivirals target specific aspects of viral replication or function, while antibiotics target bacterial structures or processes — reflecting the fundamental biological differences between viruses and bacteria","antivirals are effective against all types of pathogens equally","antiviral medications have no real mechanism of action"],"answer":1,"exp":"Antivirals target specific aspects of viral replication or function, while antibiotics target bacterial structures or processes — this difference reflects the fundamental biological differences between viruses (which rely on host cell machinery to replicate) and bacteria (which are independent cells)."},{"id":"srb124014","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"What is 'immunodeficiency'?","options":["an overactive immune system that attacks healthy tissue","a condition in which the immune system's ability to fight infections and disease is significantly reduced or absent","a synonym for herd immunity","a condition that always results from vaccination"],"answer":1,"exp":"Immunodeficiency is a condition in which the immune system's ability to fight infections and disease is significantly reduced or absent, leaving an individual more vulnerable to infections that a healthy immune system would normally handle effectively."},{"id":"srb124015","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"Which best describes how HIV (human immunodeficiency virus) specifically undermines the immune system?","options":["HIV has no significant effect on the immune system","HIV specifically targets and destroys helper T cells, which play a crucial coordinating role in the adaptive immune response, progressively weakening overall immune function","HIV strengthens the immune system over time","HIV only affects the skin, with no internal immune impact"],"answer":1,"exp":"HIV specifically targets and destroys helper T cells, which play a crucial coordinating role in the adaptive immune response, progressively weakening overall immune function and leaving the body increasingly vulnerable to other infections."},{"id":"srb124016","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"Which best describes why some diseases are particularly difficult to develop effective vaccines against, such as those caused by rapidly mutating viruses?","options":["vaccine development difficulty has no connection to how quickly a pathogen mutates","if a virus mutates rapidly, the antigens the immune system has learned to recognise may change significantly, potentially reducing the effectiveness of a vaccine targeted at an earlier viral form","all viruses mutate at exactly the same, very slow rate","vaccines are always equally effective regardless of how much a pathogen has mutated"],"answer":1,"exp":"If a virus mutates rapidly, the antigens the immune system has learned to recognise may change significantly over time, potentially reducing the effectiveness of a vaccine that was originally developed to target an earlier form of the virus — this is part of why some vaccines need regular updating."},{"id":"srb124017","state":"AU","section":"sr_biology","grade":"12","topic":"Immune Response","difficulty":"hard","style":"standard","paper":"G12-B4","q":"What is an 'allergy', in immunological terms?","options":["a beneficial immune response with no negative consequences","an exaggerated immune response to a substance that is not actually harmful to most people, sometimes causing significant symptoms or even a dangerous reaction","a synonym for an autoimmune disease","a condition unrelated to the immune system"],"answer":1,"exp":"An allergy is an exaggerated immune response to a substance (an allergen) that is not actually harmful to most people, which can sometimes cause significant symptoms or, in severe cases, a dangerous reaction such as anaphylaxis."},{"id":"srb124018","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"Which best describes why epidemiologists track the 'basic reproduction number' (R₀) of an infectious disease?","options":["R₀ has no real epidemiological significance","R₀ estimates how many new infections, on average, result from a single infected individual in a fully susceptible population, helping predict and manage the potential spread of a disease","R₀ measures the exact number of deaths caused by a disease","R₀ is only relevant for non-infectious diseases"],"answer":1,"exp":"R₀ (the basic reproduction number) estimates how many new infections, on average, result from a single infected individual within a fully susceptible population, which helps epidemiologists predict and manage the potential spread of an infectious disease."},{"id":"srb124019","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"Which best describes the relationship between R₀ and the herd immunity threshold needed to control the spread of a disease?","options":["R₀ has no connection to herd immunity thresholds","generally, a higher R₀ value means a larger proportion of the population needs to be immune to achieve herd immunity and effectively control the disease's spread","a higher R₀ always means a lower herd immunity threshold is needed","herd immunity thresholds are unrelated to how contagious a disease is"],"answer":1,"exp":"Generally, a higher R₀ value means a more contagious disease, requiring a larger proportion of the population to be immune in order to achieve herd immunity and effectively control the disease's ongoing spread."},{"id":"srb124020","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"Which best describes why public health measures such as quarantine and isolation are used during disease outbreaks?","options":["these measures have no real effect on disease transmission","separating infected or potentially infected individuals from the wider population helps reduce opportunities for disease transmission, slowing the overall spread of an outbreak","quarantine measures always eliminate a disease completely and immediately","isolation measures are only ever used for non-infectious conditions"],"answer":1,"exp":"Separating infected or potentially infected individuals from the wider population helps reduce opportunities for disease transmission, slowing the overall spread of an outbreak even before a vaccine or treatment may be available."},{"id":"srb124021","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"Which best describes the concept of an 'emerging infectious disease'?","options":["a disease that has existed in its current form for thousands of years with no change","a newly identified disease, or a known disease that has significantly increased in incidence or spread to new geographic areas or populations","a disease that has been completely eradicated","a term referring only to non-infectious chronic diseases"],"answer":1,"exp":"An emerging infectious disease is either a newly identified disease, or a previously known disease that has significantly increased in incidence or spread to new geographic areas or populations, often presenting new public health challenges."},{"id":"srb124022","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"Which best describes why genetic and behavioural factors are both considered when studying the spread of infectious disease within a population?","options":["only genetic factors are ever relevant to disease spread","both the genetic susceptibility of individuals and behavioural factors (such as hygiene practices or population density) can significantly influence how a disease spreads and who is most affected","behavioural factors have no real influence on disease transmission","genetic and behavioural factors are exactly the same thing"],"answer":1,"exp":"Both the genetic susceptibility of individuals and behavioural factors, such as hygiene practices or population density, can significantly influence how a disease spreads through a population and who is most likely to be affected."},{"id":"srb124023","state":"AU","section":"sr_biology","grade":"12","topic":"Disease","difficulty":"hard","style":"standard","paper":"G12-B4","q":"Which best summarises the relationship between the immune system, natural selection, and the ongoing 'evolutionary arms race' between hosts and pathogens?","options":["hosts and pathogens do not influence each other's evolution in any way","pathogens face selective pressure to evade host immune defences, while hosts face selective pressure to develop more effective defences, creating an ongoing evolutionary arms race between the two","this evolutionary relationship only ever favours the pathogen, never the host","the immune system has no connection to evolutionary processes"],"answer":1,"exp":"Pathogens face selective pressure to evade host immune defences (driving the evolution of immune-evasion strategies), while hosts face selective pressure to develop more effective defences against pathogens — together creating an ongoing evolutionary 'arms race' between hosts and the pathogens that infect them."},{"id":"srb124024","state":"AU","section":"sr_biology","grade":"12","topic":"Immune Response","difficulty":"hard","style":"standard","paper":"G12-B4","q":"Which best describes an 'autoimmune disease' in light of how the adaptive immune system normally distinguishes 'self' from 'non-self'?","options":["autoimmune disease involves the immune system correctly identifying only foreign cells as targets","autoimmune disease occurs when the immune system's normal ability to distinguish the body's own healthy cells ('self') from foreign invaders ('non-self') breaks down, leading it to attack the body's own tissues","autoimmune disease only affects the skin","autoimmune disease is caused exclusively by external pathogens, not by the immune system's own malfunction"],"answer":1,"exp":"Autoimmune disease occurs when the immune system's normal ability to distinguish the body's own healthy cells ('self') from foreign invaders ('non-self') breaks down, leading it to mistakenly attack the body's own tissues as though they were a threat."},{"id":"srb124025","state":"AU","section":"sr_biology","grade":"12","topic":"Immune Response","difficulty":"hard","style":"standard","paper":"G12-B4","q":"Which best describes why booster vaccine doses are sometimes recommended for certain diseases?","options":["booster doses are purely a formality with no immunological basis","immunity (antibody levels and memory cell activity) can wane over time for some diseases, so a booster dose helps restimulate the immune response and maintain stronger protection","booster doses always provide weaker protection than the original vaccine dose","booster doses are required for every vaccine without exception"],"answer":1,"exp":"For some diseases, immunity (antibody levels and memory cell activity) can wane over time, so a booster dose helps restimulate the immune response, boosting antibody levels and reinforcing memory cell activity to maintain stronger, longer-lasting protection."},{"q":"What is the function of mitochondria?","options":["Protein synthesis","ATP production via cellular respiration","DNA storage","Cell division"],"answer":1,"topic":"Cell Biology","exp":"Mitochondria: 'powerhouse of the cell'. Aerobic respiration: glucose+O₂→CO₂+H₂O+ATP. ~36-38 ATP per glucose. Inner membrane folds (cristae) increase surface area.","difficulty":"medium","id":"srbF60000016","section":"sr_biology","state":"VIC","grade":12,"style":"standard"},{"q":"What is the difference between DNA and RNA?","options":["Same molecule","DNA has deoxyribose sugar and thymine; RNA has ribose sugar and uracil. DNA is double-stranded; RNA is single-stranded","DNA is single-stranded; RNA is double-stranded","RNA contains thymine; DNA contains uracil"],"answer":1,"topic":"Molecular Biology","exp":"DNA stores genetic information. RNA types: mRNA (carries code from nucleus to ribosomes), tRNA (transfers amino acids), rRNA (forms ribosomes).","difficulty":"medium","id":"srbF60000017","section":"sr_biology","state":"VIC","grade":12,"style":"standard"},{"q":"What is a 'gene pool'?","options":["A swimming pool for genetics","The total collection of all alleles in a population","The genes in one organism","A type of DNA test"],"answer":1,"topic":"Genetics","exp":"Gene pool diversity: high = population can adapt to changes; low (e.g. cheetahs) = vulnerable to disease and environmental change. Isolation reduces gene pool.","difficulty":"hard","id":"srbF60000018","section":"sr_biology","state":"VIC","grade":12,"style":"standard"},{"q":"What is 'codominance'?","options":["One allele hiding another","Both alleles are fully expressed simultaneously in the heterozygous phenotype","One allele is dominant over the other","Neither allele is expressed"],"answer":1,"topic":"Genetics","exp":"Codominance: AB blood type (both A and B antigens expressed), roan coat in cattle (both red and white hairs). Neither allele is 'hidden'.","difficulty":"hard","id":"srbF60000019","section":"sr_biology","state":"VIC","grade":12,"style":"standard"},{"q":"What is an 'ecosystem service'?","options":["Services provided by animals","The benefits humans receive from ecosystems, such as clean water, oxygen, food, and climate regulation","A type of national park","Ecological research"],"answer":1,"topic":"Ecology","exp":"Ecosystem services: provisioning (food, water), regulating (climate, floods), cultural (recreation, spirituality), supporting (nutrient cycling, photosynthesis).","difficulty":"hard","id":"srbF60000020","section":"sr_biology","state":"VIC","grade":12,"style":"standard"},{"q":"What is 'symbiosis'?","options":["Competition between species","A long-term close interaction between two species that benefits at least one","One species eating another","Migration between habitats"],"answer":1,"topic":"Ecology","exp":"Symbiosis types: mutualism (+/+, both benefit), commensalism (+/0, one benefits, other unaffected), parasitism (+/-, one benefits at other's expense).","difficulty":"medium","id":"srbF60000021","section":"sr_biology","state":"VIC","grade":12,"style":"standard"},{"q":"What is the 'Hardy-Weinberg principle'?","options":["Natural selection always occurs","In a large, randomly mating population with no evolution, allele frequencies remain constant from generation to generation","Populations always evolve","Random mating changes allele frequencies"],"answer":1,"topic":"Genetics","exp":"H-W equilibrium requires: no mutation, no selection, no migration, random mating, large population. Deviations indicate evolution is occurring.","difficulty":"hard","id":"srbF60000022","section":"sr_biology","state":"VIC","grade":12,"style":"standard"},{"q":"What is 'enzyme specificity'?","options":["Enzymes work at all temperatures","Each enzyme catalyses only specific reactions because its active site shape matches only certain substrates","Enzymes can change shape permanently","All enzymes have the same active site"],"answer":1,"topic":"Biochemistry","exp":"Lock-and-key model: enzyme active site shape complementary to specific substrate. Induced fit model: active site slightly adjusts to substrate. Highly selective.","difficulty":"medium","id":"srbF60000023","section":"sr_biology","state":"VIC","grade":12,"style":"standard"}];